INSERT INTO `courses` (`id`, `title`, `slug`, `description`, `is_published`, `created_at`, `updated_at`) VALUES
	(1, 'Web-разработка: HTML & CSS (Deep Dive)', 'web-development-html-css-deep-dive', 'Полный курс по верстке для начинающих. От основ HTML5 до современной адаптивной верстки на Flexbox.', 1, '2026-04-23 15:24:16', '2026-04-23 15:24:16'),
	(2, 'Tailwind v4.2', 'tailwind-v42', 'Tailwind предоставляет большое разнообразие CSS-классов, каждый из которых имеет собственную функцию', 1, '2026-04-25 00:36:16', '2026-04-25 00:36:16');
INSERT INTO `lessons` (`id`, `course_id`, `module_id`, `title`, `slug`, `content`, `position`, `is_published`, `created_at`, `updated_at`) VALUES
	(1, 1, 1, 'Урок 1.1: Инфраструктура', 'urok-11-infrastruktura', '\n                            <section>\n                                <p class="lead">Добро пожаловать в мир веб-разработки! Узнаем, как устроен интернет и создадим свою первую страницу.</p>\n                                <h3>Как работает интернет?</h3>\n                                <p>Представь, что ты заказываешь пиццу:</p>\n                                <ul>\n                                    <li><b>Клиент (Браузер)</b>: Это ты. Ты вводишь адрес и нажимаешь "Enter" (делаешь заказ).</li>\n                                    <li><b>Сервер</b>: Это кухня пиццерии. Он находит нужные файлы и "готовит" страницу.</li>\n                                    <li><b>HTTP</b>: Это курьер, который доставляет готовую страницу тебе на стол.</li>\n                                </ul>\n\n                                <h3>Настройка VS Code</h3>\n                                <p>Установи эти плагины для комфортной работы:</p>\n                                <ol>\n                                    <li><code>Live Server</code> — мгновенный просмотр изменений.</li>\n                                    <li><code>Auto Rename Tag</code> — авто-правка парных тегов.</li>\n                                </ol>\n\n                                <h3>Скелет HTML-документа</h3>\n                                <p>Базовый шаблон любого сайта (в VS Code набери <code>!</code> и нажми <code>Tab</code>):</p>\n                                \n                                <pre><span class="code-header">index.html</span><code><span class="hl-comm">&lt;!-- Сообщаем браузеру, что это современный HTML5 --&gt;</span>\n<span class="hl-tag">&lt;!DOCTYPE html&gt;</span>\n<span class="hl-tag">&lt;html</span> <span class="hl-attr">lang=</span><span class="hl-str">"ru"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;head&gt;</span>\n    <span class="hl-tag">&lt;meta</span> <span class="hl-attr">charset=</span><span class="hl-str">"UTF-8"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;title&gt;</span>Моя первая страница<span class="hl-tag">&lt;/title&gt;</span>\n<span class="hl-tag">&lt;/head&gt;</span>\n<span class="hl-tag">&lt;body&gt;</span>\n    <span class="hl-comm">&lt;!-- Весь контент пишется здесь --&gt;</span>\n    Привет, мир!\n<span class="hl-tag">&lt;/body&gt;</span>\n<span class="hl-tag">&lt;/html&gt;</span></code></pre>\n\n                                <h3>Что это за теги?</h3>\n                                <ul>\n                                    <li><code>&lt;!DOCTYPE html&gt;</code> — <b>декларация</b>. Она говорит браузеру: "Эй, это современный стандарт HTML5!".</li>\n                                    <li><code>&lt;html lang="ru"&gt;</code> — корень документа.</li>\n                                    <li><code>&lt;head&gt;</code> — "голова" сайта. Здесь хранится техническая информация.</li>\n                                    <li><code>&lt;meta charset="UTF-8"&gt;</code> — кодировка. <b>UTF-8</b> поддерживает почти все языки мира.</li>\n                                    <li><code>&lt;title&gt;</code> — текст на вкладке браузера.</li>\n                                    <li><code>&lt;body&gt;</code> — "тело" сайта. Здесь находится всё, что мы видим.</li>\n                                </ul>\n                            </section>\n                        ', 1, 1, '2026-04-24 01:50:55', '2026-04-24 01:50:55'),
	(2, 1, 1, 'Урок 1.2: Текстовая иерархия', 'urok-12-tekstovaia-ierarxiia', '\n                            <section>\n                                <p>HTML — это про <b>смысл</b>. Теги говорят браузеру, что является заголовком, а что — текстом.</p>\n\n                                <h3>Заголовки (h1–h6)</h3>\n                                <div class="alert alert-important">\n                                    <span>⚠️</span>\n                                    <div>\n                                        <b>Важное правило:</b> На странице должен быть только один тег <code>&lt;h1&gt;</code>. Это главный заголовок.\n                                    </div>\n                                </div>\n\n                                <pre><code><span class="hl-tag">&lt;h1&gt;</span>Главная тема страницы<span class="hl-tag">&lt;/h1&gt;</span>\n<span class="hl-tag">&lt;h2&gt;</span>Раздел 1: Введение<span class="hl-tag">&lt;/h2&gt;</span>\n<span class="hl-tag">&lt;h3&gt;</span>Подраздел: История вопроса<span class="hl-tag">&lt;/h3&gt;</span></code></pre>\n\n                                <h3>Абзацы и Акценты</h3>\n                                <p>Для обычного текста используем тег <code>&lt;p&gt;</code>.</p>\n                                <pre><code><span class="hl-tag">&lt;p&gt;</span>Обычный текст. <span class="hl-tag">&lt;strong&gt;</span>Жирный<span class="hl-tag">&lt;/strong&gt;</span> и <span class="hl-tag">&lt;em&gt;</span>курсив<span class="hl-tag">&lt;/em&gt;</span>.<span class="hl-tag">&lt;/p&gt;</span></code></pre>\n                            </section>\n                        ', 2, 1, '2026-04-24 01:50:55', '2026-04-24 01:50:55'),
	(3, 1, 1, 'Урок 1.3: Списки и спецсимволы', 'urok-13-spiski-i-specsimvoly', '\n                            <section>\n                                <h3>Списки</h3>\n                                <p><b>Маркированные (ul)</b> — порядок не важен. <b>Нумерованные (ol)</b> — когда важна последовательность.</p>\n                                \n                                <pre><code><span class="hl-tag">&lt;ul&gt;</span>\n    <span class="hl-tag">&lt;li&gt;</span>Яблоки<span class="hl-tag">&lt;/li&gt;</span>\n    <span class="hl-tag">&lt;li&gt;</span>Бананы<span class="hl-tag">&lt;/li&gt;</span>\n<span class="hl-tag">&lt;/ul&gt;</span></code></pre>\n\n                                <h3>Спецсимволы</h3>\n                                <p>Чтобы вывести символы, которые HTML считает кодом, используем сущности:</p>\n                                <ul>\n                                    <li><code>&amp;lt;</code> — знак "меньше" (&lt;)</li>\n                                    <li><code>&amp;gt;</code> — знак "больше" (&gt;)</li>\n                                    <li><code>&amp;copy;</code> — знак копирайта (&copy;)</li>\n                                </ul>\n\n                                <div class="task-box">\n                                    <h2>🚀 Практическое задание</h2>\n                                    <p>Создай страницу-визитку о своем любимом герое или хобби:</p>\n                                    <ul>\n                                        <li>Используй правильную структуру HTML5.</li>\n                                        <li>Добавь заголовок <code>h1</code> и подзаголовок <code>h2</code>.</li>\n                                        <li>Напиши 2-3 абзаца текста с выделениями.</li>\n                                        <li>Создай список из 5 интересных фактов.</li>\n                                        <li>В конце добавь <code>&copy; Твое Имя</code>.</li>\n                                    </ul>\n                                </div>\n                            </section>\n                        ', 3, 1, '2026-04-24 01:50:55', '2026-04-24 01:50:55'),
	(4, 1, 2, 'Урок 2.1: Ссылки и атрибуты', 'urok-21-ssylki-i-atributy', '<!-- Lesson 2.1 -->\n<section id="lesson-2-1">\n    <h2>🔗 Урок 2.1: Гиперссылки и атрибуты</h2>\n    <p>Привет! Сегодня мы научимся создавать <strong>ссылки</strong>. Именно они связывают миллиарды страниц в одну паутину. За ссылки отвечает тег <code>&lt;a&gt;</code> (от англ. <em>anchor</em> — якорь).</p>\n\n    <h3>1. Базовый синтаксис</h3>\n    <p>Тег <code>&lt;a&gt;</code> всегда требует атрибут <code>href</code>. В нем мы пишем адрес сайта или путь к файлу.</p>\n    \n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"https://google.com"</span><span class="hl-tag">&gt;</span>Перейти в Google<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Результат:</strong> <a href="https://google.com" target="_blank" style="color: var(--primary); text-decoration: underline; font-weight: 500;">Перейти в Google</a>\n    </div>\n\n    <h3>2. Атрибут target (Где открыть?)</h3>\n    <p>Если ты хочешь, чтобы твой сайт остался открытым, а ссылка открылась в <strong>новой вкладке</strong>, используй <code>target="_blank"</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"https://wikipedia.org"</span> <span class="hl-attr">target=</span><span class="hl-str">"_blank"</span><span class="hl-tag">&gt;</span>Википедия в новой вкладке<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Запомни:</strong> По умолчанию ссылки открываются в той же вкладке (<code>_self</code>). Для внешних сайтов лучше всегда ставить <code>_blank</code>.\n        </div>\n    </div>\n\n    <h3>3. Всплывающая подсказка (title)</h3>\n    <p>Атрибут <code>title</code> показывает текст, когда ты наводишь мышку на ссылку.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"https://youtube.com"</span> <span class="hl-attr">title=</span><span class="hl-str">"Самый большой видеохостинг"</span><span class="hl-tag">&gt;</span>Наведи на меня!<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Результат:</strong> <a href="https://youtube.com" title="Самый большой видеохостинг" target="_blank" style="color: var(--primary); text-decoration: underline; font-weight: 500;">Наведи на меня!</a>\n    </div>\n\n    <h3>4. Функциональные ссылки</h3>\n    <p>Ссылки могут не только открывать сайты, но и предлагать написать письмо или позвонить.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Ссылка на почту --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"mailto:test@example.com"</span><span class="hl-tag">&gt;</span>Написать нам письмо<span class="hl-tag">&lt;/a&gt;</span>\n\n<span class="hl-comm">&lt;!-- Ссылка на телефон (удобно для мобильных) --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"tel:+79001112233"</span><span class="hl-tag">&gt;</span>Позвонить мастеру<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <h3>5. Картинка-ссылка</h3>\n    <p>Чтобы сделать картинку кликабельной, просто оберни тег <code>&lt;img&gt;</code> тегом <code>&lt;a&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"https://github.com"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;img</span> <span class="hl-attr">src=</span><span class="hl-str">"https://github.githubassets.com/images/modules/logos_page/GitHub-Mark.png"</span> <span class="hl-attr">width=</span><span class="hl-str">"50"</span> <span class="hl-attr">alt=</span><span class="hl-str">"GitHub"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div style="padding: 20px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05); text-align: center;">\n        <a href="https://github.com" target="_blank" style="display: inline-block; transition: transform 0.2s;" onmouseover="this.style.transform=\'scale(1.1)\'" onmouseout="this.style.transform=\'scale(1)\'">\n            <img src="https://github.githubassets.com/images/modules/logos_page/GitHub-Mark.png" width="50" alt="GitHub">\n        </a>\n        <p style="margin-top: 12px; color: var(--text-muted);"><small>Кликни по котику выше!</small></p>\n    </div>\n</section>\n\n<!-- Homework -->\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай на компьютере папку <code>my_first_site</code>.</li>\n        <li>Внутри создай файл <code>index.html</code>.</li>\n        <li>Сделай страницу со списком твоих любимых игр.</li>\n        <li>Каждое название игры должно быть ссылкой на официальный сайт этой игры.</li>\n        <li>Сделай так, чтобы ссылки открывались в новой вкладке.</li>\n        <li>Добавь внизу страницы ссылку-телефон "Техподдержка мамы" со своим номером.</li>\n    </ol>\n</div>\n', 4, 1, '2026-04-24 01:50:55', '2026-04-24 04:49:59'),
	(5, 1, 2, 'Урок 2.2: Файловая система', 'urok-22-failovaia-sistema', '<section id="lesson-2-2">\n    <h2>📁 Урок 2.2: Файловая система и пути</h2>\n    <p>Чтобы сайт не превратился в свалку файлов, разработчики раскладывают всё по папкам: картинки в <code>img</code>, стили в <code>css</code>, другие страницы в <code>pages</code>. Сегодня мы научимся объяснять браузеру, где именно лежит нужный файл.</p>\n\n    <h3>1. Абсолютные и относительные пути</h3>\n    <p>Существует два способа указать путь к файлу:</p>\n    <ul>\n        <li><strong>Абсолютный путь:</strong> Полный адрес в интернете (начинается с <code>http://</code> или <code>https://</code>).</li>\n        <li><strong>Относительный путь:</strong> Путь от текущего файла к тому, который мы хотим найти.</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Абсолютный путь (внешний сайт) --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"https://google.com"</span><span class="hl-tag">&gt;</span>На Google<span class="hl-tag">&lt;/a&gt;</span>\n\n<span class="hl-comm">&lt;!-- Относительный путь (файл в этой же папке) --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"contact.html"</span><span class="hl-tag">&gt;</span>Контакты<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <h3>2. Погружение в папки</h3>\n    <p>Если файл лежит в папке (например, картинка в папке <code>img</code>), мы сначала пишем название папки, затем косую черту <code>/</code>, а потом имя файла.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Заходим в папку img --&gt;</span>\n<span class="hl-tag">&lt;img</span> <span class="hl-attr">src=</span><span class="hl-str">"img/photo.jpg"</span> <span class="hl-attr">alt=</span><span class="hl-str">"Моё фото"</span><span class="hl-tag">&gt;</span>\n\n<span class="hl-comm">&lt;!-- Заходим в папку pages за файлом about.html --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"pages/about.html"</span><span class="hl-tag">&gt;</span>О нас<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Совет:</strong> Всегда используй для названий файлов только английские буквы, цифры и знак подчеркивания. Никаких пробелов!\n        </div>\n    </div>\n\n    <h3>3. Выход из папки (назад на уровень выше)</h3>\n    <p>Иногда нужно «выйти» из текущей папки назад. Для этого используется команда <code>../</code>. Каждая такая комбинация поднимает тебя на одну папку вверх.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Мы внутри папки pages, нам нужно выйти наружу к главной index.html --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"../index.html"</span><span class="hl-tag">&gt;</span>Вернуться на главную<span class="hl-tag">&lt;/a&gt;</span>\n\n<span class="hl-comm">&lt;!-- Выйти из текущей папки и зайти в папку img --&gt;</span>\n<span class="hl-tag">&lt;img</span> <span class="hl-attr">src=</span><span class="hl-str">"../img/logo.png"</span> <span class="hl-attr">alt=</span><span class="hl-str">"Лого"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Шпаргалка по путям:</strong>\n        <ul style="margin: 8px 0 0 0; padding-left: 20px; color: var(--text-muted);">\n            <li><code>index.html</code> — файл рядом (в той же папке).</li>\n            <li><code>img/</code> — зайти в папку img.</li>\n            <li><code>../</code> — выйти из папки назад.</li>\n            <li><code>./</code> — текущая папка (редко, но бывает нужно).</li>\n        </ul>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>В твоей папке <code>my_first_site</code> создай папку <code>img</code> и положи туда любое изображение (назови его <code>hero.jpg</code>).</li>\n        <li>Создай папку <code>pages</code> и внутри неё файл <code>hobbies.html</code>.</li>\n        <li>В главном файле <code>index.html</code>:\n            <ul>\n                <li>Вставь картинку из папки <code>img</code>.</li>\n                <li>Сделай ссылку на файл <code>hobbies.html</code>.</li>\n            </ul>\n        </li>\n        <li>В файле <code>hobbies.html</code>:\n            <ul>\n                <li>Сделай ссылку "Назад", которая вернет тебя на <code>index.html</code> (используй <code>../</code>).</li>\n            </ul>\n        </li>\n    </ol>\n</div>', 5, 1, '2026-04-24 01:50:55', '2026-04-24 04:55:23'),
	(6, 1, 2, 'Урок 2.3: Якоря и Навигация', 'urok-23-iakoria-i-navigaciia', '<section id="lesson-2-3">\n    <h2>⚓ Урок 2.3: Якоря и Навигация</h2>\n    <p>Когда страница становится очень длинной, пользователю неудобно крутить колёсико мыши. **Якоря** позволяют мгновенно перемещаться к нужному разделу страницы. Это работает как закладка в большой книге.</p>\n\n    <h3>1. Подготовка: Создаем "цель" (ID)</h3>\n    <p>Чтобы ссылка знала, куда прыгать, нам нужно дать разделу уникальное имя с помощью атрибута <code>id</code>. Это имя должно быть уникальным — один ID на одну страницу.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Даем заголовку уникальное имя "contacts" --&gt;</span>\n<span class="hl-tag">&lt;h2</span> <span class="hl-attr">id=</span><span class="hl-str">"contacts"</span><span class="hl-tag">&gt;</span>Наши контакты<span class="hl-tag">&lt;/h2&gt;</span></code></pre>\n\n    <h3>2. Создаем "телепорт" (Ссылку)</h3>\n    <p>Чтобы отправить пользователя к этому заголовку, в атрибуте <code>href</code> мы пишем символ решетки <code>#</code> и имя нашего ID.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Ссылка, которая прыгнет к элементу с id="contacts" --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"#contacts"</span><span class="hl-tag">&gt;</span>Прыгнуть к контактам<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Важно:</strong> Не забудь поставить <code>#</code> перед именем в ссылке. Если напишешь просто <code>href="contacts"</code>, браузер решит, что это отдельный файл, и выдаст ошибку 404.\n        </div>\n    </div>\n\n    <h3>3. Ссылка "Наверх"</h3>\n    <p>Часто в конце длинных страниц делают кнопку возврата в самое начало. Для этого не обязательно создавать ID для шапки, можно просто использовать <code>#</code> без имени или создать ID для самого верхнего элемента.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Простой способ вернуться в начало страницы --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"#"</span><span class="hl-tag">&gt;</span>Вверх ↑<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <h3>4. Ссылка на якорь другой страницы</h3>\n    <p>Ты можешь отправить пользователя не просто на другую страницу, а сразу в конкретный её раздел. Для этого объедини путь к файлу и якорь.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Откроет файл hobbies.html и сразу прокрутит к секции игр --&gt;</span>\n<span class="hl-tag">&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"hobbies.html#games"</span><span class="hl-tag">&gt;</span>Посмотреть мои игры<span class="hl-tag">&lt;/a&gt;</span></code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Как это работает (логика):</strong>\n        <ol style="margin: 8px 0 0 0; padding-left: 20px; color: var(--text-muted);">\n            <li>Браузер видит в ссылке знак <code>#</code>.</li>\n            <li>Он ищет на странице элемент, у которого в атрибуте <code>id</code> написано то же самое.</li>\n            <li>Как только находит — мгновенно прокручивает страницу так, чтобы этот элемент оказался сверху.</li>\n        </ol>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Возьми свой файл <code>index.html</code> и добавь в него много текста (например, 20-30 пустых абзацев <code>&lt;p&gt;&lt;/p&gt;</code>), чтобы появилась прокрутка.</li>\n        <li>В самом низу страницы создай заголовок <code>&lt;h2&gt;</code> с твоим именем и присвой ему <code>id="me"</code>.</li>\n        <li>В самом верху страницы создай ссылку "Об авторе", которая ведет на <code>#me</code>.</li>\n        <li>Рядом с заголовком внизу создай ссылку "Вернуться на старт", которая ведет на <code>#</code>.</li>\n        <li>Проверь в браузере, как работают эти "прыжки".</li>\n    </ol>\n</div>', 6, 1, '2026-04-24 01:50:55', '2026-04-24 05:37:59'),
	(7, 1, 3, 'Урок 3.1: Мультимедиа', 'urok-31-multimedia', '<section id="lesson-3-1">\n    <h2>🖼️ Урок 3.1: Мультимедиа (Изображения и видео)</h2>\n    <p>Текст — это хорошо, но картинки и видео делают сайт интересным. В HTML для этого используются специальные теги, которые не содержат текст внутри себя, а просто указывают путь к файлу.</p>\n\n    <h3>1. Тег &lt;img&gt; и его атрибуты</h3>\n    <p>Тег <code>&lt;img&gt;</code> — одиночный. Ему не нужен закрывающий тег. Самый важный атрибут здесь — <code>src</code> (source), в котором мы пишем путь к картинке.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;img</span> <span class="hl-attr">src=</span><span class="hl-str">"img/nature.jpg"</span> <span class="hl-attr">alt=</span><span class="hl-str">"Красивый лес в тумане"</span> <span class="hl-attr">width=</span><span class="hl-str">"300"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Атрибут alt — обязателен!</strong> Если картинка не загрузится (например, плохой интернет), пользователь увидит этот текст. Также его читают программы для слабовидящих людей и поисковые роботы.\n        </div>\n    </div>\n\n    <h3>2. Размеры и пропорции</h3>\n    <p>Ты можешь управлять размером картинки прямо в HTML с помощью <code>width</code> (ширина) и <code>height</code> (высота). Но будь осторожен!</p>\n    <ul>\n        <li>Если указать и ширину, и высоту, картинка может <strong>растянуться</strong> или <strong>сплющиться</strong>.</li>\n        <li>Лучше указывать только один параметр (например, только <code>width</code>), тогда браузер подберет второй автоматически, сохранив пропорции.</li>\n    </ul>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05); text-align: center;">\n        <strong>Результат (Картинка с фиксированной шириной):</strong><br><br>\n        <img src="https://images.unsplash.com/photo-1518770660439-4636190af475?w=200" alt="Микросхема" style="border-radius: 8px; border: 2px solid var(--primary);">\n        <p style="color: var(--text-muted); font-size: 0.8em;">Ширина установлена в 200px</p>\n    </div>\n\n    <h3>3. Форматы изображений</h3>\n    <p>В вебе чаще всего используют три формата:</p>\n    <ul>\n        <li><strong>JPG:</strong> Для фотографий (много цветов, мало весит).</li>\n        <li><strong>PNG:</strong> Если нужен прозрачный фон (например, логотипы).</li>\n        <li><strong>SVG:</strong> Векторная графика. Не теряет качество при любом увеличении.</li>\n    </ul>\n\n    <h3>4. Вставка видео с YouTube</h3>\n    <p>Чтобы вставить чужое видео, обычно используют тег <code>&lt;iframe&gt;</code>. Это как маленькое окно, в котором открывается другая страница (в данном случае — плеер YouTube).</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Пример вставки окна с видео --&gt;</span>\n<span class="hl-tag">&lt;iframe</span> <span class="hl-attr">width=</span><span class="hl-str">"560"</span> <span class="hl-attr">height=</span><span class="hl-str">"315"</span> <span class="hl-attr">src=</span><span class="hl-str">"https://www.youtube.com/embed/dQw4w9WgXcQ"</span> <span class="hl-attr">frameborder=</span><span class="hl-str">"0"</span> <span class="hl-attr">allowfullscreen</span><span class="hl-tag">&gt;&lt;/iframe&gt;</span></code></pre>\n\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Найди в интернете картинку своего любимого персонажа или машины. Сохрани её в папку <code>img</code> своего проекта.</li>\n        <li>Вставь эту картинку на страницу <code>index.html</code>.</li>\n        <li>Добавь атрибут <code>alt</code> с коротким описанием того, что на фото.</li>\n        <li>Попробуй изменить ширину картинки на <code>500</code>. Посмотри, что произойдет.</li>\n        <li><strong>Бонус:</strong> Зайди на YouTube, нажми "Поделиться" -> "Встроить" под любым видео, скопируй код <code>iframe</code> и вставь его к себе на сайт.</li>\n    </ol>\n</div>', 7, 1, '2026-04-24 01:50:55', '2026-04-24 05:59:16'),
	(8, 1, 3, 'Урок 3.2: Таблицы: База', 'urok-32-tablicy-baza', '<section id="lesson-3-2">\n    <h2>📊 Урок 3.2: Таблицы (Базовая структура)</h2>\n    <p>Таблица в HTML строится построчно. Представь, что ты собираешь конструктор: сначала создаешь общую коробку, затем добавляешь в неё ряды, а в ряды — отдельные ячейки.</p>\n\n    <h3>1. Основные теги</h3>\n    <ul>\n        <li><code>&lt;table&gt;</code> — главный контейнер всей таблицы.</li>\n        <li><code>&lt;tr&gt;</code> (table row) — создает строку таблицы.</li>\n        <li><code>&lt;td&gt;</code> (table data) — создает обычную ячейку с данными.</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;table&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Ячейка 1<span class="hl-tag">&lt;/td&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Ячейка 2<span class="hl-tag">&lt;/td&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n<span class="hl-tag">&lt;/table&gt;</span></code></pre>\n\n    <h3>2. Заголовки таблицы (&lt;th&gt;)</h3>\n    <p>Чтобы выделить названия столбцов, вместо обычного <code>&lt;td&gt;</code> используется тег <code>&lt;th&gt;</code> (table header). По умолчанию браузер делает текст внутри него жирным и центрирует его.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;table&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;th&gt;</span>Предмет<span class="hl-tag">&lt;/th&gt;</span>\n        <span class="hl-tag">&lt;th&gt;</span>Оценка<span class="hl-tag">&lt;/th&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Информатика<span class="hl-tag">&lt;/td&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>5<span class="hl-tag">&lt;/td&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n<span class="hl-tag">&lt;/table&gt;</span></code></pre>\n\n    \n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Результат (как это выглядит без стилей):</strong>\n        <table style="width: 100%; border-collapse: collapse; margin-top: 10px; color: var(--text-main);">\n            <thead>\n                <tr>\n                    <th style="border: 1px solid #ddd; padding: 8px; background: rgba(79, 70, 229, 0.1);">Предмет</th>\n                    <th style="border: 1px solid #ddd; padding: 8px; background: rgba(79, 70, 229, 0.1);">Оценка</th>\n                </tr>\n            </thead>\n            <tbody>\n                <tr>\n                    <td style="border: 1px solid #ddd; padding: 8px;">Информатика</td>\n                    <td style="border: 1px solid #ddd; padding: 8px;">5</td>\n                </tr>\n                <tr>\n                    <td style="border: 1px solid #ddd; padding: 8px;">Математика</td>\n                    <td style="border: 1px solid #ddd; padding: 8px;">4</td>\n                </tr>\n            </tbody>\n        </table>\n    </div>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Важное правило:</strong> Никогда не используй таблицы для создания сетки сайта (шапка, меню, колонки). Для этого существуют <strong>Flexbox</strong> и <strong>Grid</strong>, которые мы выучим позже. Таблицы — только для данных!\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай новый файл <code>schedule.html</code>.</li>\n        <li>С помощью тега <code>&lt;table&gt;</code> создай таблицу со своим расписанием уроков на завтра.</li>\n        <li>В первой строке используй теги <code>&lt;th&gt;</code> для заголовков: "Время", "Урок", "Кабинет".</li>\n        <li>Добавь минимум 4-5 строк с данными (твои уроки).</li>\n        <li><strong>Бонус:</strong> Попробуй добавить атрибут <code>border="1"</code> в тег <code>&lt;table&gt;</code>. Это старый способ добавить границы, но сейчас он поможет тебе лучше увидеть структуру таблицы.</li>\n    </ol>\n</div>', 8, 1, '2026-04-24 01:50:55', '2026-04-24 06:00:24'),
	(9, 1, 3, 'Урок 3.3: Таблицы: Сложные структуры', 'urok-33-tablicy-sloznye-struktury', '<section id="lesson-3-3">\n    <h2>🧩 Урок 3.3: Таблицы (Сложные структуры)</h2>\n    <p>Иногда нужно, чтобы одна ячейка занимала место двух или более. Например, когда один урок длится два часа или когда один заголовок относится к нескольким колонкам. Для этого используются «объединители».</p>\n\n    <h3>1. Объединение по горизонтали (colspan)</h3>\n    <p>Атрибут <code>colspan</code> (от англ. <em>column span</em>) растягивает ячейку вправо на указанное количество колонок.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;table</span> <span class="hl-attr">border=</span><span class="hl-str">"1"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;th</span> <span class="hl-attr">colspan=</span><span class="hl-str">"2"</span><span class="hl-tag">&gt;</span>Выходные дни<span class="hl-tag">&lt;/th&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Суббота<span class="hl-tag">&lt;/td&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Воскресенье<span class="hl-tag">&lt;/td&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n<span class="hl-tag">&lt;/table&gt;</span></code></pre>\n\n    <h3>2. Объединение по вертикали (rowspan)</h3>\n    <p>Атрибут <code>rowspan</code> растягивает ячейку вниз. Это полезно, если одно и то же значение повторяется в нескольких строках подряд.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;table</span> <span class="hl-attr">border=</span><span class="hl-str">"1"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;th&gt;</span>Время<span class="hl-tag">&lt;/th&gt;</span>\n        <span class="hl-tag">&lt;th&gt;</span>Событие<span class="hl-tag">&lt;/th&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;td</span> <span class="hl-attr">rowspan=</span><span class="hl-str">"2"</span><span class="hl-tag">&gt;</span>09:00<span class="hl-tag">&lt;/td&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Завтрак<span class="hl-tag">&lt;/td&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;tr&gt;</span>\n        <span class="hl-tag">&lt;td&gt;</span>Зарядка<span class="hl-tag">&lt;/td&gt;</span>\n    <span class="hl-tag">&lt;/tr&gt;</span>\n<span class="hl-tag">&lt;/table&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Важно:</strong> Если ты объединил ячейки с помощью <code>colspan="2"</code>, значит в этой строке следующая ячейка <code>&lt;td&gt;</code> «съедается». Не забудь удалить лишние теги, иначе таблица «поплывет».\n        </div>\n    </div>\n\n    <h3>3. Семантическая разметка (Группировка)</h3>\n    <p>Для больших таблиц профессионалы используют специальные теги-контейнеры. Это помогает браузерам и поисковикам лучше понимать структуру данных.</p>\n    <ul>\n        <li><code>&lt;thead&gt;</code> — «голова» таблицы (заголовки).</li>\n        <li><code>&lt;tbody&gt;</code> — основное тело таблицы (данные).</li>\n        <li><code>&lt;tfoot&gt;</code> — «подвал» таблицы (итоги или примечания).</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;table&gt;</span>\n    <span class="hl-tag">&lt;thead&gt;</span>\n        <span class="hl-tag">&lt;tr&gt;</span><span class="hl-tag">&lt;th&gt;</span>Товар<span class="hl-tag">&lt;/th&gt;</span><span class="hl-tag">&lt;th&gt;</span>Цена<span class="hl-tag">&lt;/th&gt;</span><span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;/thead&gt;</span>\n    <span class="hl-tag">&lt;tbody&gt;</span>\n        <span class="hl-tag">&lt;tr&gt;</span><span class="hl-tag">&lt;td&gt;</span>Яблоко<span class="hl-tag">&lt;/td&gt;</span><span class="hl-tag">&lt;td&gt;</span>100 р.<span class="hl-tag">&lt;/td&gt;</span><span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;/tbody&gt;</span>\n    <span class="hl-tag">&lt;tfoot&gt;</span>\n        <span class="hl-tag">&lt;tr&gt;</span><span class="hl-tag">&lt;td&gt;</span>Итого:<span class="hl-tag">&lt;/td&gt;</span><span class="hl-tag">&lt;td&gt;</span>100 р.<span class="hl-tag">&lt;/td&gt;</span><span class="hl-tag">&lt;/tr&gt;</span>\n    <span class="hl-tag">&lt;/tfoot&gt;</span>\n<span class="hl-tag">&lt;/table&gt;</span></code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальная шпаргалка по объединению:</strong>\n        \n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Открой файл <code>schedule.html</code>, который ты сделал в прошлом уроке.</li>\n        <li>Используй <code>colspan</code>, чтобы сделать заголовок "Моё расписание" на всю ширину таблицы (в самой первой строке).</li>\n        <li>Если у тебя есть сдвоенный урок (например, две Алгебры подряд), объедини время для этих уроков с помощью <code>rowspan</code>.</li>\n        <li>Оберни заголовки в <code>&lt;thead&gt;</code>, а основное расписание в <code>&lt;tbody&gt;</code>.</li>\n        <li>В самом низу добавь <code>&lt;tfoot&gt;</code>, в котором напиши "Всего уроков: 6" (используй <code>colspan</code>, чтобы растянуть эту ячейку).</li>\n    </ol>\n</div>', 9, 1, '2026-04-24 01:50:55', '2026-04-24 06:21:37'),
	(10, 1, 4, 'Урок 4.1: Основы форм', 'urok-41-osnovy-form', '<section id="lesson-4-1">\n    <h2>📝 Урок 4.1: Основы форм</h2>\n    <p>Форма — это специальная область на странице, где пользователь может вводить данные. Представь анкету: ты заполняешь поля, а потом нажимаешь кнопку «Отправить». В HTML всё работает точно так же.</p>\n\n    <h3>1. Контейнер &lt;form&gt;</h3>\n    <p>Все элементы ввода (поля, кнопки) должны находиться внутри тега <code>&lt;form&gt;</code>. У этого тега есть два важных атрибута:</p>\n    <ul>\n        <li><code>action</code> — адрес (URL), куда полетят данные после отправки.</li>\n        <li><code>method</code> — способ отправки (чаще всего <code>GET</code> или <code>POST</code>).</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;form</span> <span class="hl-attr">action=</span><span class="hl-str">"/send-data"</span> <span class="hl-attr">method=</span><span class="hl-str">"POST"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-comm">&lt;!-- Здесь будут поля ввода --&gt;</span>\n<span class="hl-tag">&lt;/form&gt;</span></code></pre>\n\n    <h3>2. Текстовые поля ввода (&lt;input&gt;)</h3>\n    <p>Тег <code>&lt;input&gt;</code> — одиночный. Его вид зависит от атрибута <code>type</code>. Давай разберем основные типы для текста:</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Обычный текст --&gt;</span>\n<span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"text"</span> <span class="hl-attr">placeholder=</span><span class="hl-str">"Ваше имя"</span><span class="hl-tag">&gt;</span>\n\n<span class="hl-comm">&lt;!-- Поле для пароля (символы скрыты) --&gt;</span>\n<span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"password"</span> <span class="hl-attr">placeholder=</span><span class="hl-str">"Пароль"</span><span class="hl-tag">&gt;</span>\n\n<span class="hl-comm">&lt;!-- Поле для почты (проверяет наличие @) --&gt;</span>\n<span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"email"</span> <span class="hl-attr">placeholder=</span><span class="hl-str">"Email"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <h3>3. Подписи к полям (&lt;label&gt;)</h3>\n    <p>Просто поле ввода — это непонятно. Пользователь должен знать, что вводить. Тег <code>&lt;label&gt;</code> создает текстовую подпись и связывает её с полем через <code>id</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;label</span> <span class="hl-attr">for=</span><span class="hl-str">"user-login"</span><span class="hl-tag">&gt;</span>Логин:<span class="hl-tag">&lt;/label&gt;</span>\n<span class="hl-tag">&lt;input</span> <span class="hl-attr">id=</span><span class="hl-str">"user-login"</span> <span class="hl-attr">type=</span><span class="hl-str">"text"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Зачем это нужно?</strong> Если ты нажмешь на текст в <code>&lt;label&gt;</code>, курсор автоматически прыгнет в связанное поле ввода. Это очень удобно, особенно на смартфонах!\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Как это выглядит в сборе:</strong>\n        <div style="margin-top: 10px; display: flex; flex-direction: column; gap: 10px; max-width: 250px;">\n            <div>\n                <label style="display: block; font-size: 14px; margin-bottom: 4px;">Ваше имя:</label>\n                <input type="text" placeholder="Иван" style="width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 6px;">\n            </div>\n            <div>\n                <label style="display: block; font-size: 14px; margin-bottom: 4px;">Ваш пароль:</label>\n                <input type="password" placeholder="••••••" style="width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 6px;">\n            </div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай новый файл <code>feedback.html</code>.</li>\n        <li>Добавь заголовок "Напиши мне письмо".</li>\n        <li>Создай форму <code>&lt;form&gt;</code>.</li>\n        <li>Внутри формы сделай три блока:\n            <ul>\n                <li>Метка "Имя" + текстовое поле.</li>\n                <li>Метка "Твой Email" + поле типа email.</li>\n                <li>Метка "Пароль для секретов" + поле типа password.</li>\n            </ul>\n        </li>\n        <li>Свяжи все <code>&lt;label&gt;</code> с их <code>&lt;input&gt;</code> с помощью атрибутов <code>for</code> и <code>id</code>.</li>\n        <li>Используй атрибут <code>placeholder</code>, чтобы дать подсказку внутри полей (например: "ivan@mail.ru").</li>\n    </ol>\n</div>', 10, 1, '2026-04-24 01:50:55', '2026-04-24 06:23:37'),
	(11, 1, 4, 'Урок 4.2: Выбор и списки', 'urok-42-vybor-i-spiski', '<section id="lesson-4-2">\n    <h2>🔘 Урок 4.2: Выбор и списки</h2>\n    <p>Иногда пользователю не нужно ничего печатать — ему нужно просто выбрать один или несколько готовых вариантов. Для этого в HTML есть переключатели, галочки и выпадающие списки.</p>\n\n    <h3>1. Радиокнопки (Одиночный выбор)</h3>\n    <p>Используются, когда нужно выбрать только **один** вариант из списка (например, пол или выбор тарифа). Чтобы они работали как одна группа, у них должен быть одинаковый атрибут <code>name</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"radio"</span> <span class="hl-attr">name=</span><span class="hl-str">"color"</span> <span class="hl-attr">id=</span><span class="hl-str">"red"</span> <span class="hl-attr">value=</span><span class="hl-str">"red"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;label</span> <span class="hl-attr">for=</span><span class="hl-str">"red"</span><span class="hl-tag">&gt;</span>Красный<span class="hl-tag">&lt;/label&gt;</span>\n\n<span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"radio"</span> <span class="hl-attr">name=</span><span class="hl-str">"color"</span> <span class="hl-attr">id=</span><span class="hl-str">"blue"</span> <span class="hl-attr">value=</span><span class="hl-str">"blue"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;label</span> <span class="hl-attr">for=</span><span class="hl-str">"blue"</span><span class="hl-tag">&gt;</span>Синий<span class="hl-tag">&lt;/label&gt;</span></code></pre>\n\n    <h3>2. Чекбоксы (Множественный выбор)</h3>\n    <p>Тег <code>&lt;input type="checkbox"&gt;</code> позволяет выбрать сразу несколько вариантов или просто поставить галочку "Согласен с условиями".</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"checkbox"</span> <span class="hl-attr">id=</span><span class="hl-str">"pizza"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;label</span> <span class="hl-attr">for=</span><span class="hl-str">"pizza"</span><span class="hl-tag">&gt;</span>Хочу пиццу<span class="hl-tag">&lt;/label&gt;</span></code></pre>\n\n    <h3>3. Выпадающий список (&lt;select&gt;)</h3>\n    <p>Если вариантов очень много, лучше спрятать их в выпадающий список, чтобы не занимать место на странице.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;label</span> <span class="hl-attr">for=</span><span class="hl-str">"city"</span><span class="hl-tag">&gt;</span>Выберите город:<span class="hl-tag">&lt;/label&gt;</span>\n<span class="hl-tag">&lt;select</span> <span class="hl-attr">id=</span><span class="hl-str">"city"</span> <span class="hl-attr">name=</span><span class="hl-str">"city"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;option</span> <span class="hl-attr">value=</span><span class="hl-str">"msk"</span><span class="hl-tag">&gt;</span>Москва<span class="hl-tag">&lt;/option&gt;</span>\n    <span class="hl-tag">&lt;option</span> <span class="hl-attr">value=</span><span class="hl-str">"spb"</span><span class="hl-tag">&gt;</span>Питер<span class="hl-tag">&lt;/option&gt;</span>\n<span class="hl-tag">&lt;/select&gt;</span></code></pre>\n\n    \n\n    <h3>4. Кнопка отправки</h3>\n    <p>Самый важный элемент — кнопка, которая скажет браузеру: "Все готово, отправляй!". Обычно это <code>&lt;button type="submit"&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;button</span> <span class="hl-attr">type=</span><span class="hl-str">"submit"</span><span class="hl-tag">&gt;</span>Отправить анкету<span class="hl-tag">&lt;/button&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Не забывай про name:</strong> Поля ввода без атрибута <code>name</code> не отправляются на сервер. Это как письмо без подписи — сервер не поймет, что это за данные.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Интерактивный пример:</strong>\n        <div style="margin-top: 12px; color: var(--text-main);">\n            <p style="margin-bottom: 8px;">Выбери уровень сложности:</p>\n            <input type="radio" name="lvl" id="easy"> <label for="easy">Легко</label>\n            <input type="radio" name="lvl" id="hard"> <label for="hard">Сложно</label>\n            <br><br>\n            <input type="checkbox" id="sub"> <label for="sub">Подписаться на новости</label>\n            <br><br>\n            <button type="button" style="padding: 8px 16px; background: var(--primary); color: white; border: none; border-radius: 6px; cursor: pointer;">Готово!</button>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Открой свой файл <code>feedback.html</code> из прошлого урока.</li>\n        <li>Добавь в форму выбор твоего любимого школьного предмета (используй <code>radio</code>, минимум 3 варианта).</li>\n        <li>Добавь чекбокс с текстом "Я согласен получать спам" (шутка, просто "Я согласен с правилами").</li>\n        <li>Создай выпадающий список <code>&lt;select&gt;</code>, где пользователь может выбрать свою страну.</li>\n        <li>В самом конце формы обязательно добавь кнопку <code>&lt;button type="submit"&gt;</code>.</li>\n        <li><strong>Проверка:</strong> Нажми на кнопку в браузере. Если страница обновилась — поздравляю, твоя форма работает!</li>\n    </ol>\n</div>', 11, 1, '2026-04-24 01:50:55', '2026-04-24 06:25:20'),
	(12, 1, 4, 'Урок 4.3: Кнопки и Валидация', 'urok-43-knopki-i-validaciia', '<section id="lesson-4-3">\n    <h2>✅ Урок 4.3: Кнопки и Валидация</h2>\n    <p>Представь, что пользователь нажал «Отправить», не введя имя или почту. Чтобы не получать пустые письма, мы установим «фильтры» прямо в HTML. Это называется <strong>валидацией</strong>.</p>\n\n    <h3>1. Кнопки: не только для отправки</h3>\n    <p>Мы уже знаем про кнопку отправки, но у тега <code>&lt;button&gt;</code> есть три разных типа:</p>\n    <ul>\n        <li><code>type="submit"</code> — отправляет данные формы (по умолчанию).</li>\n        <li><code>type="reset"</code> — мгновенно очищает все поля формы.</li>\n        <li><code>type="button"</code> — просто кнопка, которая ничего не делает (пока мы не добавим ей магию с помощью JavaScript).</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;button</span> <span class="hl-attr">type=</span><span class="hl-str">"submit"</span><span class="hl-tag">&gt;</span>Отправить<span class="hl-tag">&lt;/button&gt;</span>\n<span class="hl-tag">&lt;button</span> <span class="hl-attr">type=</span><span class="hl-str">"reset"</span><span class="hl-tag">&gt;</span>Сбросить всё<span class="hl-tag">&lt;/button&gt;</span></code></pre>\n\n    <h3>2. Атрибут required (Обязательное поле)</h3>\n    <p>Если добавить этот атрибут к полю <code>&lt;input&gt;</code>, браузер не даст отправить форму, пока поле пустое. Он сам покажет предупреждение: «Заполните это поле».</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"text"</span> <span class="hl-attr">required</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <h3>3. Ограничение длины (minlength и maxlength)</h3>\n    <p>Полезно, если ты хочешь, чтобы пароль был не короче 8 символов или никнейм не длиннее 20.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"password"</span> <span class="hl-attr">minlength=</span><span class="hl-str">"8"</span> <span class="hl-attr">maxlength=</span><span class="hl-str">"16"</span> <span class="hl-attr">required</span><span class="hl-tag">&gt;</span></code></pre>\n\n    \n\n    <h3>4. Подсказки и шаблоны</h3>\n    <p>Мы можем подсказать браузеру, какие данные мы ждем, используя типы полей и атрибут <code>placeholder</code>.</p>\n    <ul>\n        <li><code>type="number"</code> — разрешит вводить только цифры.</li>\n        <li><code>placeholder</code> — серый текст-подсказка внутри поля.</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;input</span> <span class="hl-attr">type=</span><span class="hl-str">"number"</span> <span class="hl-attr">min=</span><span class="hl-str">"12"</span> <span class="hl-attr">max=</span><span class="hl-str">"18"</span> <span class="hl-attr">placeholder=</span><span class="hl-str">"Твой возраст"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Интересный факт:</strong> Если ты используешь <code>type="email"</code>, браузер сам проверит, есть ли в тексте символ <code>@</code> и точка. Тебе не нужно ничего программировать!\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Пример работающей валидации:</strong>\n        <form style="margin-top: 10px; display: flex; flex-direction: column; gap: 10px; max-width: 300px;">\n            <input type="text" placeholder="Имя (обязательно)" required style="padding: 8px; border: 1px solid #ccc; border-radius: 6px;">\n            <input type="password" placeholder="Пароль (мин. 6 знаков)" minlength="6" required style="padding: 8px; border: 1px solid #ccc; border-radius: 6px;">\n            <div style="display: flex; gap: 10px;">\n                <button type="submit" style="flex: 1; padding: 8px; background: var(--primary); color: white; border: none; border-radius: 6px; cursor: pointer;">Отправить</button>\n                <button type="reset" style="padding: 8px; background: #eee; border: none; border-radius: 6px; cursor: pointer;">Очистить</button>\n            </div>\n        </form>\n        <p style="margin-top: 8px; color: var(--text-muted); font-size: 0.8em;">Попробуй нажать «Отправить» с пустыми полями.</p>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Открой файл <code>feedback.html</code>.</li>\n        <li>Сделай поля "Имя" и "Email" обязательными для заполнения (<code>required</code>).</li>\n        <li>Для поля "Пароль" установи минимальную длину в 8 символов.</li>\n        <li>Добавь новое поле для ввода возраста (<code>type="number"</code>) и ограничь его: минимум 7, максимум 100 лет.</li>\n        <li>Добавь кнопку <code>type="reset"</code> с текстом "Стереть и начать заново".</li>\n        <li><strong>Финальный тест:</strong> Попробуй ввести в поле Email просто слово "привет" и нажать отправить. Посмотри, что скажет браузер.</li>\n    </ol>\n</div>', 12, 1, '2026-04-24 01:50:55', '2026-04-24 06:27:04'),
	(13, 1, 5, 'Урок 5.1: Семантический HTML5', 'urok-51-semanticeskii-html5', '<section id="lesson-5-1">\n    <h2>🏗️ Урок 5.1: Семантический HTML5</h2>\n    <p>Раньше разработчики строили сайты из одинаковых «коробок» — тегов <code>&lt;div&gt;</code>. Но когда коробок становится слишком много, поисковики перестают понимать, где на сайте меню, а где важная статья. Семантика дает каждой «коробке» уникальный смысл.</p>\n\n    <h3>1. Зачем это нужно?</h3>\n    <ul>\n        <li><strong>SEO (Поисковики):</strong> Google и Яндекс лучше понимают структуру и ставят сайт выше в поиске.</li>\n        <li><strong>Доступность:</strong> Программы-диктофоны читают сайт вслух для слабовидящих людей, ориентируясь на теги.</li>\n        <li><strong>Порядок в коде:</strong> Тебе самому будет проще разобраться в структуре через месяц.</li>\n    </ul>\n\n    <h3>2. Основные структурные теги</h3>\n    <p>Вместо безликих <code>&lt;div&gt;</code> теперь мы используем "говорящие" теги:</p>\n    <ul>\n        <li><code>&lt;header&gt;</code> — шапка сайта (логотип, поиск, верхнее меню).</li>\n        <li><code>&lt;nav&gt;</code> — навигационная панель (основные ссылки сайта).</li>\n        <li><code>&lt;main&gt;</code> — главное содержимое страницы (должен быть один на странице).</li>\n        <li><code>&lt;section&gt;</code> — крупный смысловой блок (например, "О нас" или "Услуги").</li>\n        <li><code>&lt;article&gt;</code> — самостоятельный текст (статья в блоге, новость, комментарий).</li>\n        <li><code>&lt;aside&gt;</code> — боковая панель (реклама, ссылки на другие статьи).</li>\n        <li><code>&lt;footer&gt;</code> — подвал сайта (контакты, авторские права).</li>\n    </ul>\n\n    \n\n    <h3>3. Пример правильной структуры</h3>\n    <p>Посмотри, как профессионально выглядит код, когда каждый блок на своем месте:</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;header&gt;</span>\n    <span class="hl-tag">&lt;h1&gt;</span>Мой крутой блог<span class="hl-tag">&lt;/h1&gt;</span>\n    <span class="hl-tag">&lt;nav&gt;</span>\n        <span class="hl-tag">&lt;ul&gt;</span>\n            <span class="hl-tag">&lt;li&gt;&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"#"</span><span class="hl-tag">&gt;</span>Главная<span class="hl-tag">&lt;/a&gt;&lt;/li&gt;</span>\n            <span class="hl-tag">&lt;li&gt;&lt;a</span> <span class="hl-attr">href=</span><span class="hl-str">"#"</span><span class="hl-tag">&gt;</span>Статьи<span class="hl-tag">&lt;/a&gt;&lt;/li&gt;</span>\n        <span class="hl-tag">&lt;/ul&gt;</span>\n    <span class="hl-tag">&lt;/nav&gt;</span>\n<span class="hl-tag">&lt;/header&gt;</span>\n\n<span class="hl-tag">&lt;main&gt;</span>\n    <span class="hl-tag">&lt;article&gt;</span>\n        <span class="hl-tag">&lt;h2&gt;</span>Как я выучил HTML<span class="hl-tag">&lt;/h2&gt;</span>\n        <span class="hl-tag">&lt;p&gt;</span>Это было захватывающее путешествие...<span class="hl-tag">&lt;/p&gt;</span>\n    <span class="hl-tag">&lt;/article&gt;</span>\n<span class="hl-tag">&lt;/main&gt;</span>\n\n<span class="hl-tag">&lt;footer&gt;</span>\n    <span class="hl-tag">&lt;p&gt;</span>&copy; 2026 Моя Первая Веб-Студия<span class="hl-tag">&lt;/p&gt;</span>\n<span class="hl-tag">&lt;/footer&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Совет:</strong> Не старайся заменить абсолютно все <code>&lt;div&gt;</code>. Если тебе нужно просто обернуть пару элементов для красоты (дизайна) — используй <code>div</code>. Если блок несет смысл — используй семантический тег.\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Возьми свой файл <code>index.html</code>.</li>\n        <li>Переделай его структуру:\n            <ul>\n                <li>Оберни верхнее меню в теги <code>&lt;header&gt;</code> и <code>&lt;nav&gt;</code>.</li>\n                <li>Основной контент (твои рассказы, игры) оберни в <code>&lt;main&gt;</code>.</li>\n                <li>Раздели контент на логические блоки с помощью <code>&lt;section&gt;</code>.</li>\n                <li>В самый низ добавь <code>&lt;footer&gt;</code> со своим именем и текущим годом.</li>\n            </ul>\n        </li>\n        <li>Проверь страницу в браузере. Визуально ничего не должно измениться, но теперь твой код стал «взрослым»!</li>\n    </ol>\n</div>', 13, 1, '2026-04-24 01:50:55', '2026-04-24 06:28:47'),
	(14, 1, 5, 'Урок 5.2: Блочная модель (Теория)', 'urok-52-blocnaia-model-teoriia', '<section id="lesson-5-2">\n    <h2>📦 Урок 5.2: Блочная модель (Теория)</h2>\n    <p>В вебе нет кругов, треугольников или сложных фигур. Для браузера абсолютно каждый элемент — это прямоугольный ящик (Box). Даже если картинка круглая, она всё равно лежит внутри невидимого прямоугольника.</p>\n\n    <h3>1. Из чего состоит "коробка"?</h3>\n    <p>Каждый элемент на странице — это как картина в раме. У него есть четыре слоя:</p>\n    <ul>\n        <li><strong>Content (Контент):</strong> Сама «картина» — текст или изображение.</li>\n        <li><strong>Padding (Внутренний отступ):</strong> Пустое место вокруг картины, чтобы она не прилипала к раме.</li>\n        <li><strong>Border (Рамка):</strong> Та самая рама вокруг контента и отступов.</li>\n        <li><strong>Margin (Внешний отступ):</strong> Расстояние от этой картины до соседних картин на стене.</li>\n    </ul>\n\n    \n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Запомни разницу:</strong> <code>Padding</code> — это место <strong>внутри</strong> коробки (между текстом и рамкой). <code>Margin</code> — это место <strong>снаружи</strong> коробки (расстояние до соседа).\n        </div>\n    </div>\n\n    <h3>2. Блочные элементы (Block)</h3>\n    <p>Такие элементы — «эгоисты». Они всегда начинаются с новой строки и растягиваются на всю ширину страницы, даже если внутри всего одно слово.</p>\n    <p><strong>Примеры:</strong> <code>&lt;div&gt;</code>, <code>&lt;h1&gt;</code>, <code>&lt;p&gt;</code>, <code>&lt;header&gt;</code>, <code>&lt;li&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;p</span> <span class="hl-attr">style=</span><span class="hl-str">"background: lightblue;"</span><span class="hl-tag">&gt;</span>Я блочный, я занял всю строку!<span class="hl-tag">&lt;/p&gt;</span>\n<span class="hl-tag">&lt;p</span> <span class="hl-attr">style=</span><span class="hl-str">"background: lightcoral;"</span><span class="hl-tag">&gt;</span>А я из-за него ушел вниз.<span class="hl-tag">&lt;/p&gt;</span></code></pre>\n\n    <h3>3. Строчные элементы (Inline)</h3>\n    <p>Эти элементы — «дружелюбные». Они занимают ровно столько места, сколько нужно их контенту, и спокойно стоят в одной строке друг с другом.</p>\n    <p><strong>Примеры:</strong> <code>&lt;span&gt;</code>, <code>&lt;a&gt;</code>, <code>&lt;strong&gt;</code>, <code>&lt;img&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;span</span> <span class="hl-attr">style=</span><span class="hl-str">"background: yellow;"</span><span class="hl-tag">&gt;</span>Мы в одной<span class="hl-tag">&lt;/span&gt;</span>\n<span class="hl-tag">&lt;span</span> <span class="hl-attr">style=</span><span class="hl-str">"background: lime;"</span><span class="hl-tag">&gt;</span>строке!<span class="hl-tag">&lt;/span&gt;</span></code></pre>\n\n    \n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Почему это важно?</strong>\n        <p style="margin-top: 8px; color: var(--text-muted);">Когда ты начнешь учить CSS, ты поймешь, что для <strong>Inline</strong> элементов нельзя просто так задать ширину или высоту — они их проигнорируют. А вот <strong>Block</strong> элементы слушаются беспрекословно.</p>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>boxes.html</code>.</li>\n        <li>Создай три абзаца <code>&lt;p&gt;</code>. Каждому из них добавь атрибут <code>style="border: 1px solid red;"</code>.</li>\n        <li>Посмотри в браузере, как рамки растянулись на всю ширину. Это подтверждает, что <code>p</code> — блочный.</li>\n        <li>Внутри одного из абзацев оберни пару слов в тег <code>&lt;span&gt;</code> и дай ему <code>style="border: 1px solid green;"</code>.</li>\n        <li>Увидишь, что зеленая рамка обвела только сами слова — это строчный элемент.</li>\n        <li><strong>Вопрос на засыпку:</strong> Если положить <code>&lt;div&gt;</code> внутрь <code>&lt;span&gt;</code>, страница «сломается». Как думаешь, почему? (Подсказка: большой ящик нельзя запихнуть в маленькую строку).</li>\n    </ol>\n</div>', 14, 1, '2026-04-24 01:50:55', '2026-04-24 06:30:35'),
	(15, 1, 5, 'Урок 5.3: Meta-теги и HEAD', 'urok-53-meta-tegi-i-head', '<section id="lesson-5-3">\n    <h2>🧠 Урок 5.3: Meta-теги и раздел HEAD</h2>\n    <p>Если тег <code>&lt;body&gt;</code> — это тело сайта, то <code>&lt;head&gt;</code> — это его мозг. Здесь хранятся инструкции для браузера, настройки кодировки, иконка вкладки и информация для поисковиков (SEO).</p>\n\n    <h3>1. Кодировка (Charset)</h3>\n    <p>Чтобы вместо русского текста пользователь не увидел непонятные знаки («кракозябры»), мы должны указать стандарт кодировки <strong>UTF-8</strong>. Это первое, что должен видеть браузер.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;meta</span> <span class="hl-attr">charset=</span><span class="hl-str">"UTF-8"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <h3>2. Адаптивность (Viewport)</h3>\n    <p>Без этого тега твой сайт на телефоне будет выглядеть как крошечная копия компьютерной версии. Тег <code>viewport</code> заставляет сайт подстраиваться под ширину экрана устройства.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;meta</span> <span class="hl-attr">name=</span><span class="hl-str">"viewport"</span> <span class="hl-attr">content=</span><span class="hl-str">"width=device-width, initial-scale=1.0"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <h3>3. Заголовок и описание (SEO)</h3>\n    <p>Тег <code>&lt;title&gt;</code> — это название вкладки в браузере. А <code>description</code> — это тот текст, который ты видишь в Google или Яндексе под ссылкой на сайт.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">&lt;title&gt;</span>Мой первый сайт<span class="hl-tag">&lt;/title&gt;</span>\n<span class="hl-tag">&lt;meta</span> <span class="hl-attr">name=</span><span class="hl-str">"description"</span> <span class="hl-attr">content=</span><span class="hl-str">"Обучающий сайт ученика 9 класса о веб-разработке"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    \n\n    <h3>4. Иконка вкладки (Favicon)</h3>\n    <p>Маленькая картинка рядом с названием сайта во вкладке называется <strong>Фавикон</strong>. Она помогает пользователю быстро найти твой сайт среди десятка открытых вкладок.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Подключаем иконку (файл должен лежать в папке проекта) --&gt;</span>\n<span class="hl-tag">&lt;link</span> <span class="hl-attr">rel=</span><span class="hl-str">"icon"</span> <span class="hl-attr">href=</span><span class="hl-str">"favicon.ico"</span> <span class="hl-attr">type=</span><span class="hl-str">"image/x-icon"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Важно:</strong> Все <code>&lt;meta&gt;</code> и <code>&lt;link&gt;</code> теги являются одиночными. Им не нужна закрывающая пара. Они просто передают данные через атрибуты.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Как выглядит идеальный "скелет" HEAD:</strong>\n        <pre style="margin-top: 10px; background: none; border: none; padding: 0;"><code><span class="hl-tag">&lt;head&gt;</span>\n    <span class="hl-tag">&lt;meta</span> <span class="hl-attr">charset=</span><span class="hl-str">"UTF-8"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;meta</span> <span class="hl-attr">name=</span><span class="hl-str">"viewport"</span> <span class="hl-attr">content=</span><span class="hl-str">"width=device-width"</span><span class="hl-tag">&gt;</span>\n    <span class="hl-tag">&lt;title&gt;</span>Название сайта<span class="hl-tag">&lt;/title&gt;</span>\n    <span class="hl-tag">&lt;link</span> <span class="hl-attr">rel=</span><span class="hl-str">"stylesheet"</span> <span class="hl-attr">href=</span><span class="hl-str">"style.css"</span><span class="hl-tag">&gt;</span>\n<span class="hl-tag">&lt;/head&gt;</span></code></pre>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Возьми свой основной файл <code>index.html</code>.</li>\n        <li>Проверь, есть ли в нем <code>&lt;meta charset="UTF-8"&gt;</code>. Если нет — добавь обязательно.</li>\n        <li>Измени содержимое тега <code>&lt;title&gt;</code> на "Портфолио [Твое Имя]".</li>\n        <li>Добавь описание сайта (description), чтобы поисковики знали, о чем твоя страница.</li>\n        <li><strong>Творческое задание:</strong> Найди в интернете любую маленькую картинку (формат .png или .ico), переименуй её в <code>favicon.ico</code>, положи в папку с проектом и подключи её. Проверь, появилась ли она на вкладке браузера.</li>\n    </ol>\n</div>', 15, 1, '2026-04-24 01:50:55', '2026-04-24 06:32:06'),
	(16, 1, 6, 'Урок 6.1: Введение в CSS', 'urok-61-vvedenie-v-css', '<section id="lesson-6-1">\n    <h2>🎨 Урок 6.1: Введение в CSS</h2>\n    <p>До этого момента наши страницы выглядели как документы из 90-х. <strong>CSS</strong> — это язык стилей, который говорит браузеру: «сделай этот заголовок красным, добавь отступ кнопке и поставь картинку в центр».</p>\n\n    <h3>1. Как устроен CSS (Синтаксис)</h3>\n    <p>Правило CSS состоит из двух частей: <strong>Селектор</strong> (кого красим) и <strong>Декларация</strong> (какой стиль применяем).</p>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">h1</span> {\n    <span class="hl-attr">color</span>: <span class="hl-str">royalblue</span>;\n    <span class="hl-attr">font-size</span>: <span class="hl-str">24px</span>;\n}</code></pre>\n\n    <p>В этом примере <code>h1</code> — это селектор, <code>color</code> — свойство, а <code>royalblue</code> — значение.</p>\n\n    <h3>2. Три способа подключения CSS</h3>\n    <p>Есть три способа добавить стили на страницу, но в профессиональной разработке используется только один.</p>\n    <ul>\n        <li><strong>Внешний файл (Лучший способ):</strong> Все стили пишутся в отдельном файле <code>style.css</code>.</li>\n        <li><strong>Внутри тега &lt;style&gt;:</strong> Стили пишутся прямо в <code>head</code> страницы.</li>\n        <li><strong>Инлайново (Внутри тега):</strong> Атрибут <code>style="..."</code> у конкретного тега.</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- Как правильно подключать CSS в HEAD --&gt;</span>\n<span class="hl-tag">&lt;link</span> <span class="hl-attr">rel=</span><span class="hl-str">"stylesheet"</span> <span class="hl-attr">href=</span><span class="hl-str">"style.css"</span><span class="hl-tag">&gt;</span></code></pre>\n\n    <h3>3. Первые свойства: Цвет и Фон</h3>\n    <p>Самые простые свойства, с которых мы начнем:</p>\n    <ul>\n        <li><code>color</code> — цвет текста.</li>\n        <li><code>background-color</code> — цвет фона элемента.</li>\n        <li><code>text-align</code> — выравнивание текста (left, center, right).</li>\n    </ul>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Важно:</strong> В CSS после каждого свойства обязательно ставится <strong>точка с запятой (;)</strong>. Если её забыть, браузер не поймет следующее правило, и весь дизайн «сломается».\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Пример оформления заголовка:</strong>\n        <div style="margin-top: 10px; padding: 20px; background: white; border-radius: 8px; text-align: center;">\n            <h1 style="color: #4F46E5; margin: 0; font-family: sans-serif;">Привет, CSS!</h1>\n            <p style="color: #6B7280;">Этот текст стал стильным.</p>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>В твоей папке <code>my_first_site</code> создай новый пустой файл и назови его <code>style.css</code>.</li>\n        <li>Открой свой <code>index.html</code> и внутри тега <code>&lt;head&gt;</code> подключи этот файл через тег <code>&lt;link&gt;</code>.</li>\n        <li>В файле <code>style.css</code> напиши код, который:\n            <ul>\n                <li>Красит все заголовки <code>h1</code> в твой любимый цвет.</li>\n                <li>Делает фон всей страницы (тег <code>body</code>) светло-серым.</li>\n                <li>Выравнивает все параграфы <code>p</code> по центру.</li>\n            </ul>\n        </li>\n        <li>Обнови страницу в браузере. Если цвета изменились — ты официально начал путь дизайнера!</li>\n    </ol>\n</div>', 16, 1, '2026-04-24 01:50:55', '2026-04-24 06:45:33'),
	(17, 1, 6, 'Урок 6.2: Селекторы и Каскад', 'urok-62-selektory-i-kaskad', '<section id="lesson-6-2">\n    <h2>🎯 Урок 6.2: Селекторы и Каскад</h2>\n    <p>Представь, что на странице 10 кнопок, но только одна из них должна быть «опасной» (красной). Чтобы выбрать именно её, в CSS используются классы и ID. Это как имена и фамилии для элементов.</p>\n\n    <h3>1. Классы (.className) — Самый частый выбор</h3>\n    <p>Класс можно дать любому количеству элементов. Это как группа людей в одинаковой форме. В HTML мы пишем <code>class="name"</code>, а в CSS ставим <strong>точку</strong> перед именем.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">/* В CSS выбираем через точку */</span>\n<span class="hl-tag">.text-green</span> {\n    <span class="hl-attr">color</span>: <span class="hl-str">green</span>;\n}</code></pre>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">&lt;!-- В HTML даем класс --&gt;</span>\n<span class="hl-tag">&lt;p</span> <span class="hl-attr">class=</span><span class="hl-str">"text-green"</span><span class="hl-tag">&gt;</span>Я зеленый текст<span class="hl-tag">&lt;/p&gt;</span>\n<span class="hl-tag">&lt;span</span> <span class="hl-attr">class=</span><span class="hl-str">"text-green"</span><span class="hl-tag">&gt;</span>И я тоже!<span class="hl-tag">&lt;/span&gt;</span></code></pre>\n\n    <h3>2. Идентификаторы (#idName) — Уникальный код</h3>\n    <p>ID — это уникальное имя. На одной странице может быть только один элемент с таким ID. В CSS перед именем ставится <strong>решетка</strong>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">#main-title</span> {\n    <span class="hl-attr">text-transform</span>: <span class="hl-str">uppercase</span>;\n    <span class="hl-attr">letter-spacing</span>: <span class="hl-str">2px</span>;\n}</code></pre>\n\n    \n\n    <h3>3. Каскад и Приоритеты (Кто главнее?)</h3>\n    <p>Что будет, если мы прикажем тегу <code>&lt;p&gt;</code> быть синим, а его классу — красным? В CSS есть иерархия (сила селектора):</p>\n    <ol>\n        <li><strong>Inline-стили</strong> (атрибут <code>style="..."</code>) — Самые мощные.</li>\n        <li><strong>ID</strong> — Очень сильные.</li>\n        <li><strong>Классы</strong> — Средние.</li>\n        <li><strong>Теги</strong> — Самые слабые.</li>\n    </ol>\n\n    \n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Важно:</strong> Если два правила имеют одинаковую силу (например, два разных цвета для одного класса), победит то, которое написано <strong>ниже</strong> в файле CSS. Это и есть "Каскад".\n        </div>\n    </div>\n\n    <h3>4. Атомная бомба CSS: !important</h3>\n    <p>Если в конце значения дописать <code>!important</code>, это правило перебьет всё остальное, даже inline-стили. </p>\n    <p><strong>Никогда не используй это просто так!</strong> Это признак плохого кода. Используй только в крайних случаях, когда нужно перебить стили сторонних библиотек.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.force-black</span> {\n    <span class="hl-attr">color</span>: <span class="hl-str">black !important</span>;\n}</code></pre>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Шпаргалка:</strong>\n        <ul style="margin: 8px 0 0 0; padding-left: 20px; color: var(--text-muted);">\n            <li><code>p { ... }</code> — Все параграфы.</li>\n            <li><code>.nav { ... }</code> — Все элементы с классом nav.</li>\n            <li><code>#logo { ... }</code> — Только один элемент с ID logo.</li>\n        </ul>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>В своем файле <code>index.html</code> создай три кнопки <code>&lt;button&gt;</code>.</li>\n        <li>Первой кнопке дай класс <code>btn-success</code>, второй — <code>btn-danger</code>, а третьей — уникальный <code>id="btn-special"</code>.</li>\n        <li>В файле <code>style.css</code>:\n            <ul>\n                <li>Покрась <code>.btn-success</code> в зеленый цвет.</li>\n                <li>Покрась <code>.btn-danger</code> в красный.</li>\n                <li>Для <code>#btn-special</code> задай желтый цвет и сделай текст жирным.</li>\n            </ul>\n        </li>\n        <li>Попробуй дать кнопке и класс, и ID одновременно, а потом покрась их в разные цвета в CSS. Посмотри, какой цвет победит (спойлер: ID сильнее!).</li>\n    </ol>\n</div>', 17, 1, '2026-04-24 01:50:55', '2026-04-24 06:51:53'),
	(18, 1, 6, 'Урок 6.3: Цвет и Текст', 'urok-63-cvet-i-tekst', '<section id="lesson-6-3">\n    <h2>🎨 Урок 6.3: Цвет и Текст</h2>\n    <p>Цвет и шрифт — это «настроение» твоего сайта. Сегодня мы разберем, как задавать цвета профессионально и как сделать текст читабельным и красивым.</p>\n\n    <h3>1. Три способа задать цвет</h3>\n    <p>В CSS есть несколько форматов записи цвета:</p>\n    <ul>\n        <li><strong>Имена:</strong> <code>red</code>, <code>gold</code>, <code>skyblue</code> (всего около 140 названий).</li>\n        <li><strong>HEX-коды:</strong> Шестнадцатеричный код, начинающийся с решетки. Например, <code>#4F46E5</code>.</li>\n        <li><strong>RGB / RGBA:</strong> Смешивание Красного, Зеленого и Синего. Буква <code>a</code> отвечает за <strong>прозрачность</strong>.</li>\n    </ul>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.box</span> {\n    <span class="hl-attr">background-color</span>: <span class="hl-str">#4f46e5</span>; <span class="hl-comm">/* Красивый фиолетовый */</span>\n    <span class="hl-attr">color</span>: <span class="hl-str">rgba(255, 255, 255, 0.8)</span>; <span class="hl-comm">/* Белый на 80% прозрачности */</span>\n}</code></pre>\n\n    <h3>2. Основы типографики</h3>\n    <p>Чтобы текст было удобно читать, мы управляем его размером, жирностью и семейством шрифтов:</p>\n    <ul>\n        <li><code>font-size</code> — размер текста (обычно в <code>px</code> или <code>rem</code>).</li>\n        <li><code>font-weight</code> — жирность (от <code>100</code> до <code>900</code> или словами <code>bold</code>).</li>\n        <li><code>line-height</code> — межстрочный интервал (чтобы строки не слипались).</li>\n    </ul>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">p</span> {\n    <span class="hl-attr">font-size</span>: <span class="hl-str">18px</span>;\n    <span class="hl-attr">font-weight</span>: <span class="hl-str">400</span>;\n    <span class="hl-attr">line-height</span>: <span class="hl-str">1.5</span>;\n}</code></pre>\n\n    <h3>3. Подключение Google Fonts</h3>\n    <p>Стандартные шрифты вроде *Times New Roman* скучные. Профессионалы используют **Google Fonts**. Чтобы подключить шрифт:</p>\n    <ol>\n        <li>Выбери шрифт на сайте fonts.google.com.</li>\n        <li>Скопируй тег <code>&lt;link&gt;</code> и вставь его в свой <code>&lt;head&gt;</code>.</li>\n        <li>Укажи название шрифта в CSS через свойство <code>font-family</code>.</li>\n    </ol>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">/* Использование подключенного шрифта Montserrat */</span>\n<span class="hl-tag">body</span> {\n    <span class="hl-attr">font-family</span>: <span class="hl-str">\'Montserrat\'</span>, sans-serif;\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Совет по дизайну:</strong> Не используй на одной странице больше 2-х разных шрифтов. Обычно один выбирают для заголовков, а другой — для основного текста.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Интерактивная проба:</strong>\n        <div style="margin-top: 12px;">\n            <h4 style="color: #e11d48; font-family: serif; font-size: 24px; margin-bottom: 5px;">Заголовок Serif</h4>\n            <p style="color: #1e293b; font-family: sans-serif; line-height: 1.6;">Это основной текст без засечек (Sans-serif). Он читается гораздо легче на экранах мониторов и телефонов.</p>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Зайди на <a href="https://fonts.google.com" target="_blank" style="color: var(--primary);">Google Fonts</a> и выбери один шрифт, который тебе нравится (например, <em>Roboto</em> или <em>Oswald</em>).</li>\n        <li>Подключи его в свой проект через <code>&lt;link&gt;</code>.</li>\n        <li>В файле <code>style.css</code>:\n            <ul>\n                <li>Примени этот шрифт ко всему телу сайта (<code>body</code>).</li>\n                <li>Найди HEX-код красивого цвета (можно на сайте <em>coolors.co</em>) и покрась им заголовки.</li>\n                <li>Сделай текст параграфов чуть крупнее (<code>18px</code>) и увеличь межстрочный интервал до <code>1.6</code>.</li>\n            </ul>\n        </li>\n        <li>Попробуй сделать один из параграфов полупрозрачным с помощью <code>rgba</code>.</li>\n    </ol>\n</div>', 18, 1, '2026-04-24 01:50:55', '2026-04-24 06:53:11'),
	(19, 1, 7, 'Урок 7.1: Геометрия блока', 'urok-71-geometriia-bloka', '<section id="lesson-7-1">\n    <h2>📦 Урок 7.1: Геометрия блока</h2>\n    <p>Мы уже знаем, что каждый элемент — это прямоугольник. Сегодня мы заглянем внутрь этого прямоугольника и научимся управлять его размерами. Это база, без которой невозможно сделать ровную верстку.</p>\n\n    <h3>1. Из чего состоит блок? (Box Model)</h3>\n    <p>Любой элемент на странице состоит из четырех слоев. Представь, что ты отправляешь по почте хрупкую вазу:</p>\n    <ul>\n        <li><strong>Content (Ваза):</strong> Самый центр. Текст, картинка или видео.</li>\n        <li><strong>Padding (Пупырчатая пленка):</strong> Внутренний отступ. Защищает контент от стенок коробки.</li>\n        <li><strong>Border (Картонная коробка):</strong> Рамка. Она имеет толщину и цвет.</li>\n        <li><strong>Margin (Расстояние между коробками):</strong> Внешний отступ. Чтобы коробки на складе не стояли вплотную.</li>\n    </ul>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.my-box</span> {\n    <span class="hl-attr">width</span>: <span class="hl-str">300px</span>;\n    <span class="hl-attr">padding</span>: <span class="hl-str">20px</span>;\n    <span class="hl-attr">border</span>: <span class="hl-str">5px solid black</span>;\n    <span class="hl-attr">margin</span>: <span class="hl-str">30px</span>;\n}</code></pre>\n\n    <h3>2. Проблема "Лишних пикселей"</h3>\n    <p>По умолчанию в CSS ширина (<code>width</code>) — это только ширина <strong>контента</strong>. Если ты задашь блоку ширину 300px, но добавишь 20px отступов и 5px рамки, то реальная ширина блока станет 350px (300 + 20*2 + 5*2). Это часто ломает верстку!</p>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Решение: box-sizing: border-box.</strong> Это магическое свойство заставляет браузер включать отступы и рамки в общую ширину. Если ты сказал 300px — блок останется 300px, а место под отступы заберется "внутрь".\n        </div>\n    </div>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">/* Ставим это правило для ВСЕХ элементов сайта */</span>\n<span class="hl-tag">*</span> {\n    <span class="hl-attr">box-sizing</span>: <span class="hl-str">border-box</span>;\n}</code></pre>\n\n    <h3>3. Краткая запись (Shorthand)</h3>\n    <p>Чтобы не писать <code>padding-top</code>, <code>padding-right</code> и так далее, можно использовать сокращенную запись. Она читается <strong>по часовой стрелке</strong> (начиная с 12 часов):</p>\n    <ul>\n        <li><code>padding: 10px 20px 30px 40px;</code> (Верх, Право, Низ, Лево)</li>\n        <li><code>padding: 10px 20px;</code> (Верх/Низ по 10px, Право/Лево по 20px)</li>\n        <li><code>padding: 10px;</code> (Со всех сторон по 10px)</li>\n    </ul>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n    <strong>Визуальный пример (Padding в действии):</strong>\n    <div style="margin-top: 12px; display: flex; gap: 20px; flex-wrap: wrap;">\n        \n        <div style="width: 160px; height: 120px; background: #e0e7ff; border: 3px solid var(--primary); padding: 10px;">\n            <div style="background: white; height: 100%; display: flex; align-items: center; justify-content: center; font-size: 12px; text-align: center; border: 1px dashed #999;">\n                Padding: 10px\n            </div>\n        </div>\n\n        <div style="width: 160px; height: 120px; background: #e0e7ff; border: 3px solid var(--primary); padding: 30px;">\n            <div style="background: white; height: 100%; display: flex; align-items: center; justify-content: center; font-size: 12px; text-align: center; border: 1px dashed #999;">\n                Padding: 30px\n            </div>\n        </div>\n\n    </div>\n    <p style="margin-top: 12px; color: var(--text-muted); font-size: 0.85em;">\n        Голубая область — это <b>Padding</b>. Белая область — это <b>Content</b>. Видишь, как при 30px контенту становится "тесно", потому что отступы забирают место внутри?\n    </p>\n</div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>В начале своего <code>style.css</code> добавь правило для всех элементов (<code>*</code>), установив <code>box-sizing: border-box</code>.</li>\n        <li>Создай в HTML блок <code>&lt;div class="card"&gt;</code>, а внутри него — заголовок и текст.</li>\n        <li>В CSS для <code>.card</code> задай:\n            <ul>\n                <li>Ширину <code>300px</code>.</li>\n                <li>Внутренние отступы <code>20px</code> со всех сторон.</li>\n                <li>Рамку <code>2px solid #ccc</code>.</li>\n                <li>Внешний отступ <code>margin: 50px auto;</code> (этот прием поставит блок ровно по центру страницы).</li>\n            </ul>\n        </li>\n        <li>Попробуй изменить <code>padding</code> и посмотри, увеличится ли сам блок (если <code>border-box</code> работает, блок останется прежнего размера).</li>\n    </ol>\n</div>', 19, 1, '2026-04-24 01:50:55', '2026-04-24 06:57:29'),
	(20, 1, 7, 'Урок 7.2: Размеры и Единицы', 'urok-72-razmery-i-edinicy', '<section id="lesson-7-2">\n    <h2>📏 Урок 7.2: Размеры и Единицы измерения</h2>\n    <p>В веб-разработке размеры можно задавать жестко (в пикселях) или гибко (в процентах и других единицах). Умение их сочетать — это и есть секрет качественного дизайна, который не «разваливается» на разных экранах.</p>\n\n    <h3>1. Пиксели (px) — Абсолютная точность</h3>\n    <p>Пиксель — это точка на экране. Если ты задал <code>width: 300px;</code>, блок будет ровно такого размера везде. Это удобно для мелких деталей: рамок, иконок или фиксированных отступов.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.box-static</span> {\n    <span class="hl-attr">width</span>: <span class="hl-str">250px</span>;\n    <span class="hl-attr">height</span>: <span class="hl-str">100px</span>;\n    <span class="hl-attr">background</span>: <span class="hl-str">#fbbf24</span>;\n}</code></pre>\n\n    <h3>2. Проценты (%) — Относительно родителя</h3>\n    <p>Размер в процентах всегда считается от ширины «родительского» элемента. Если <code>&lt;body&gt;</code> занимает весь экран, то блок <code>width: 50%</code> займет ровно половину окна браузера.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.box-fluid</span> {\n    <span class="hl-attr">width</span>: <span class="hl-str">50%</span>;\n    <span class="hl-attr">background</span>: <span class="hl-str">#10b981</span>;\n}</code></pre>\n\n    <h3>3. rem — Для идеального текста</h3>\n    <p><code>1rem</code> равен размеру шрифта корня страницы (обычно 16px). Если пользователь увеличит масштаб текста в настройках телефона, элементы в <code>rem</code> тоже аккуратно увеличатся. Это стандарт современной разработки.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">h2</span> {\n    <span class="hl-attr">font-size</span>: <span class="hl-str">2.5rem</span>; <span class="hl-comm">/* Это 40px, если база 16px */</span>\n    <span class="hl-attr">margin-bottom</span>: <span class="hl-str">1rem</span>;\n}</code></pre>\n\n    \n\n    <h3>4. vh и vw — Размер экрана (Viewport)</h3>\n    <p>Эти единицы привязаны к размеру окна браузера целиком:</p>\n    <ul>\n        <li><code>100vw</code> — вся ширина окна.</li>\n        <li><code>100vh</code> — вся высота окна.</li>\n    </ul>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Совет:</strong> Используй <code>rem</code> для шрифтов и отступов, <code>%</code> для ширины колонок, а <code>px</code> — для тонких рамок и мелких элементов, которые не должны менять размер.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальное сравнение:</strong>\n        <div style="margin-top: 12px; display: flex; flex-direction: column; gap: 10px;">\n            <div style="width: 200px; background: #fbbf24; color: #000; padding: 10px; font-size: 12px; border-radius: 4px;">\n                Я всегда 200px (Фиксированный)\n            </div>\n            <div style="width: 70%; background: #10b981; color: #fff; padding: 10px; font-size: 12px; border-radius: 4px;">\n                Я 70% ширины (Резиновый)\n            </div>\n        </div>\n        <p style="margin-top: 10px; color: var(--text-muted); font-size: 0.85em;">Попробуй сузить окно браузера — зеленый блок начнет уменьшаться вместе с ним, а желтый останется прежним.</p>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>units.html</code>.</li>\n        <li>Внутри <code>body</code> создай контейнер <code>&lt;div class="container"&gt;</code> и дай ему ширину <code>80%</code> и <code>margin: 0 auto;</code> (чтобы он был по центру).</li>\n        <li>Внутри контейнера создай три блока:\n            <ul>\n                <li>Первый: ширина <code>200px</code>, цвет красный.</li>\n                <li>Второй: ширина <code>50%</code>, цвет синий.</li>\n                <li>Третий: ширина <code>20vw</code>, цвет зеленый.</li>\n            </ul>\n        </li>\n        <li>Для заголовка страницы установи размер <code>3rem</code>.</li>\n        <li>Подвигай окно браузера и посмотри, как ведут себя блоки. Обрати внимание, что <code>50%</code> считается от контейнера, а <code>20vw</code> — от всего экрана!</li>\n    </ol>\n</div>', 20, 1, '2026-04-24 01:50:55', '2026-04-24 06:59:14'),
	(21, 1, 7, 'Урок 7.3: Фон и Границы', 'urok-73-fon-i-granicy', '<section id="lesson-7-3">\n    <h2>🎨 Урок 7.3: Фон и Границы</h2>\n    <p>Теперь, когда мы умеем выставлять размеры блоков, пришло время заняться их внешним видом. Мы научимся работать с цветами фона, рамками и эффектами, которые делают элементы объемными и современными.</p>\n\n    <h3>1. Продвинутый фон (Градиенты)</h3>\n    <p>Вместо скучного одного цвета можно использовать <code>linear-gradient</code>. Это плавный переход из одного цвета в другой. Ты можешь указать направление (например, <code>to right</code>) и любые цвета.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.gradient-box</span> {\n    <span class="hl-attr">background</span>: <span class="hl-str">linear-gradient(to right, #4f46e5, #ec4899)</span>;\n}</code></pre>\n\n    \n\n    <h3>2. Скругление углов (border-radius)</h3>\n    <p>Острые углы часто выглядят грубо. Свойство <code>border-radius</code> позволяет их смягчить. Если задать значение <code>50%</code> для квадратного блока, он превратится в идеальный круг.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.button</span> {\n    <span class="hl-attr">border-radius</span>: <span class="hl-str">8px</span>; <span class="hl-comm">/* Слегка скругленные углы */</span>\n}\n<span class="hl-tag">.avatar</span> {\n    <span class="hl-attr">border-radius</span>: <span class="hl-str">50%</span>; <span class="hl-comm">/* Круглое фото */</span>\n}</code></pre>\n\n    <h3>3. Тени (box-shadow)</h3>\n    <p>Тени создают эффект глубины, как будто элемент «парит» над страницей. У тени 4 основных параметра: сдвиг по X, сдвиг по Y, размытие и цвет.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.card</span> {\n    <span class="hl-comm">/* сдвиг-X сдвиг-Y размытие цвет */</span>\n    <span class="hl-attr">box-shadow</span>: <span class="hl-str">0px 4px 15px rgba(0, 0, 0, 0.1)</span>;\n}</code></pre>\n\n    \n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Совет:</strong> Не делай тени слишком черными и резкими. Хорошая тень почти незаметна глазу, она просто создает ощущение объема. Используй <code>rgba</code> с низкой прозрачностью (0.1 или 0.2).\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальный пример (Стильная карточка):</strong>\n        <div style="margin-top: 15px; display: flex; justify-content: center;">\n            <div style="width: 250px; padding: 20px; background: white; border-radius: 15px; box-shadow: 0 10px 25px rgba(0,0,0,0.1); border: 1px solid #eee; text-align: center;">\n                <div style="width: 60px; height: 60px; background: linear-gradient(135deg, #4f46e5, #ec4899); border-radius: 50%; margin: 0 auto 15px;"></div>\n                <h4 style="margin: 0 0 10px 0; color: #1f2937;">Дизайн-карта</h4>\n                <p style="margin: 0; font-size: 14px; color: #6b7280; line-height: 1.4;">Здесь есть градиент, скругление и мягкая тень.</p>\n            </div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай в HTML блок <code>&lt;div class="magic-card"&gt;</code>.</li>\n        <li>В CSS для этого блока:\n            <ul>\n                <li>Задай размеры (например, <code>300px</code> на <code>200px</code>).</li>\n                <li>Сделай фон в виде линейного градиента из твоего любимого цвета в белый.</li>\n                <li>Скругли углы на <code>20px</code>.</li>\n                <li>Добавь красивую рамку <code>2px solid</code> цветом из градиента.</li>\n                <li>Добавь тень, которая будет уходить немного вниз и вправо.</li>\n            </ul>\n        </li>\n        <li><strong>Эксперимент:</strong> Попробуй изменить <code>border-radius</code> на <code>100px 0px 100px 0px</code>. Посмотри, какую необычную форму примет блок!</li>\n    </ol>\n</div>', 21, 1, '2026-04-24 01:50:55', '2026-04-24 07:00:14'),
	(22, 1, 8, 'Урок 8.1: Display', 'urok-81-display', '<section id="lesson-8-1">\n    <h2>🛠️ Урок 8.1: Свойство Display</h2>\n    <p>Свойство <code>display</code> — это «правила поведения» элемента на странице. Оно решает, будет ли элемент вести себя как наглый блок, занимающий всё место, или как вежливая строка, готовая потесниться.</p>\n\n    <h3>1. display: block (Блочные)</h3>\n    <p>Элемент растягивается на всю доступную ширину. Следующий за ним элемент всегда перепрыгивает на новую строку. Блокам можно задавать любые размеры (<code>width</code>, <code>height</code>) и любые отступы.</p>\n    <p><strong>Примеры:</strong> <code>&lt;div&gt;</code>, <code>&lt;h1&gt;</code>, <code>&lt;p&gt;</code>, <code>&lt;section&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.block-element</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">block</span>;\n    <span class="hl-attr">background</span>: <span class="hl-str">#8b5cf6</span>;\n    <span class="hl-attr">width</span>: <span class="hl-str">100%</span>;\n}</code></pre>\n\n    <h3>2. display: inline (Строчные)</h3>\n    <p>Элемент занимает ровно столько места, сколько нужно его содержимому. Соседи могут стоять с ним в одной строке. <strong>Внимание:</strong> строчным элементам нельзя задать ширину и высоту (они их проигнорируют), а вертикальные отступы работают некорректно.</p>\n    <p><strong>Примеры:</strong> <code>&lt;span&gt;</code>, <code>&lt;a&gt;</code>, <code>&lt;strong&gt;</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.inline-element</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">inline</span>;\n    <span class="hl-attr">background</span>: <span class="hl-str">#fbbf24</span>;\n}</code></pre>\n\n    \n\n    <h3>3. display: inline-block (Гибрид)</h3>\n    <p>Это «суперсила», объединяющая лучшее от обоих миров. Элементы выстраиваются в ряд (как строчные), но при этом слушаются команд по ширине, высоте и отступам (как блочные). Идеально для кнопок и карточек в ряд.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.menu-item</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">inline-block</span>;\n    <span class="hl-attr">width</span>: <span class="hl-str">120px</span>;\n    <span class="hl-attr">margin</span>: <span class="hl-str">5px</span>;\n    <span class="hl-attr">text-align</span>: <span class="hl-str">center</span>;\n}</code></pre>\n\n    <h3>4. display: none (Исчезновение)</h3>\n    <p>Полностью удаляет элемент с экрана. Он не просто становится прозрачным, он перестает занимать место, как будто его никогда и не было на странице. Часто используется для скрытых меню, которые выпадают при клике.</p>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Не путай с visibility: hidden!</strong> Свойство <code>visibility: hidden</code> делает элемент невидимым, но пустое место от него остается. А <code>display: none</code> «схлопывает» это место.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальное сравнение:</strong>\n        <div style="margin-top: 12px;">\n            <div style="display: block; background: #8b5cf6; color: white; padding: 5px; margin-bottom: 5px; border-radius: 4px;">Я - Block (занял всё)</div>\n            <span style="display: inline; background: #fbbf24; padding: 5px; border-radius: 4px;">Я - Inline</span>\n            <span style="display: inline; background: #fbbf24; padding: 5px; border-radius: 4px;">Я тоже Inline</span>\n            <div style="margin-top: 10px;">\n                <div style="display: inline-block; width: 80px; background: #10b981; color: white; padding: 5px; text-align: center; border-radius: 4px;">I-Block</div>\n                <div style="display: inline-block; width: 80px; background: #10b981; color: white; padding: 5px; text-align: center; border-radius: 4px;">I-Block</div>\n            </div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>display.html</code>.</li>\n        <li>Создай 5 ссылок <code>&lt;a&gt;</code>. По умолчанию они строчные и стоят в ряд.</li>\n        <li>В CSS преврати их в блочные (<code>display: block</code>). Посмотри, как они выстроились в колонку.</li>\n        <li>А теперь преврати их в <code>inline-block</code>. Задай им ширину <code>150px</code>, <code>margin</code> и цвет фона. Теперь это похоже на кнопки меню!</li>\n        <li>Попробуй одному из элементов задать <code>display: none</code> и посмотри, как остальные кнопки "подвинутся", занимая его место.</li>\n    </ol>\n</div>', 22, 1, '2026-04-24 01:50:55', '2026-04-24 07:01:22'),
	(23, 1, 8, 'Урок 8.2: Position', 'urok-82-position', '<section id="lesson-8-2">\n    <h2>📍 Урок 8.2: Позиционирование (Position)</h2>\n    <p>По умолчанию все элементы на странице стоят друг за другом в строгом порядке (это называется «поток»). Но иногда нужно вырваться из этого потока: например, приклеить меню к верху страницы или поставить иконку прямо поверх картинки. Для этого нужно свойство <code>position</code>.</p>\n\n    <h3>1. position: relative (Относительное)</h3>\n    <p>Элемент остается на своем месте, но получает возможность немного «сдвинуться» относительно своей начальной точки с помощью команд <code>top</code>, <code>bottom</code>, <code>left</code>, <code>right</code>. При этом он всё еще занимает свое старое место, и соседи его не заменяют.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.box-relative</span> {\n    <span class="hl-attr">position</span>: <span class="hl-str">relative</span>;\n    <span class="hl-attr">top</span>: <span class="hl-str">20px</span>; <span class="hl-comm">/* Сдвинулся вниз на 20px от своего места */</span>\n    <span class="hl-attr">left</span>: <span class="hl-str">10px</span>;\n}</code></pre>\n\n    <h3>2. position: absolute (Абсолютное)</h3>\n    <p>Элемент «вылетает» из потока. Он больше не занимает место, и соседи смыкаются под ним. Он перемещается относительно ближайшего родителя, у которого стоит <code>position: relative</code>.</p>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-comm">/* Родитель */</span>\n<span class="hl-tag">.parent</span> { <span class="hl-attr">position</span>: <span class="hl-str">relative</span>; }\n\n<span class="hl-comm">/* Ребенок, который "прилипнет" к правому верхнему углу родителя */</span>\n<span class="hl-tag">.child</span> {\n    <span class="hl-attr">position</span>: <span class="hl-str">absolute</span>;\n    <span class="hl-attr">top</span>: <span class="hl-str">0</span>;\n    <span class="hl-attr">right</span>: <span class="hl-str">0</span>;\n}</code></pre>\n\n    <h3>3. position: fixed (Фиксированное)</h3>\n    <p>Элемент приклеивается к <strong>окну браузера</strong>. Даже если ты будешь листать страницу вниз, он останется на месте. Так делают «липкие» шапки сайтов или кнопки чата в углу.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.header</span> {\n    <span class="hl-attr">position</span>: <span class="hl-str">fixed</span>;\n    <span class="hl-attr">top</span>: <span class="hl-str">0</span>;\n    <span class="hl-attr">width</span>: <span class="hl-str">100%</span>;\n}</code></pre>\n\n    <h3>4. z-index (Слои)</h3>\n    <p>Когда элементы начинают накладываться друг на друга, нам нужно решить, кто будет сверху. Свойство <code>z-index</code> — это номер слоя. Чем выше число, тем «ближе» к тебе находится элемент.</p>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.modal-window</span> {\n    <span class="hl-attr">z-index</span>: <span class="hl-str">999</span>; <span class="hl-comm">/* Будет поверх всех остальных элементов */</span>\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Главная ловушка:</strong> <code>z-index</code> работает только у тех элементов, у которых <code>position</code> НЕ является <code>static</code> (стандартным). Сначала задай позицию, а потом — слой.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05); min-height: 120px; position: relative;">\n        <strong>Визуальный пример слоев:</strong>\n        <div style="position: absolute; top: 40px; left: 20px; width: 60px; height: 60px; background: #8b5cf6; border-radius: 8px; z-index: 1; display: flex; align-items: center; justify-content: center; color: white;">z: 1</div>\n        <div style="position: absolute; top: 60px; left: 50px; width: 60px; height: 60px; background: #ec4899; border-radius: 8px; z-index: 2; display: flex; align-items: center; justify-content: center; color: white;">z: 2</div>\n        <div style="position: absolute; top: 80px; left: 80px; width: 60px; height: 60px; background: #10b981; border-radius: 8px; z-index: 3; display: flex; align-items: center; justify-content: center; color: white;">z: 3</div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>position.html</code>.</li>\n        <li>Создай <code>&lt;div class="container"&gt;</code> и положи в него картинку.</li>\n        <li>Сделай контейнер <code>relative</code>.</li>\n        <li>Внутри контейнера создай <code>&lt;span class="badge"&gt;NEW&lt;/span&gt;</code>.</li>\n        <li>С помощью <code>position: absolute</code> поставь этот бейджик "NEW" прямо в правый верхний угол картинки.</li>\n        <li>Создай кнопку "Вверх" и с помощью <code>position: fixed</code> закрепи её в правом нижнем углу самого окна браузера (с отступом 20px).</li>\n        <li>Добавь на страницу много текста, чтобы появилась прокрутка, и проверь, что кнопка "Вверх" всегда на месте.</li>\n    </ol>\n</div>', 23, 1, '2026-04-24 01:50:55', '2026-04-24 07:02:31'),
	(24, 1, 8, 'Урок 8.3: Центрирование', 'urok-83-centrirovanie', '<section id="lesson-8-3">\n    <h2>🎯 Урок 8.3: Искусство центрирования</h2>\n    <p>Поставить элемент ровно по центру — задача, которая раньше была настоящим вызовом. Мы разберем три сценария: как центрировать текст, как центрировать блок и как сделать «идеальный центр».</p>\n\n    <h3>1. Центрирование текста</h3>\n    <p>Для текста и строчных элементов (<code>span</code>, <code>a</code>, <code>img</code>) всё просто. Мы говорим родителю выровнять содержимое по центру.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.parent</span> {\n    <span class="hl-attr">text-align</span>: <span class="hl-str">center</span>;\n}</code></pre>\n\n    <h3>2. Центрирование блоков (margin: auto)</h3>\n    <p>Чтобы отцентрировать <code>div</code> по горизонтали, мы задаем ему ширину и автоматические отступы по бокам. Браузер сам поделит пустое место поровну.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.block</span> {\n    <span class="hl-attr">width</span>: <span class="hl-str">300px</span>;\n    <span class="hl-attr">margin</span>: <span class="hl-str">0 auto</span>;\n}</code></pre>\n\n    <h3>3. Идеальный центр (Absolute + Transform)</h3>\n    <p>Когда нужно поставить элемент в центр и по горизонтали, и по вертикали, мы используем связку координат и трансформации.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.centered</span> {\n    <span class="hl-attr">position</span>: <span class="hl-str">absolute</span>;\n    <span class="hl-attr">top</span>: <span class="hl-str">50%</span>;\n    <span class="hl-attr">left</span>: <span class="hl-str">50%</span>;\n    <span class="hl-attr">transform</span>: <span class="hl-str">translate(-50%, -50%)</span>;\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>🧩</span>\n        <div>\n            <strong>Разбор "магии" translate:</strong>\n            <p style="margin-top: 5px;">1. Команды <code>top: 50%</code> и <code>left: 50%</code> ставят в центр страницы <strong>угол</strong> нашего блока. Из-за этого блок кажется смещенным вправо и вниз.</p>\n            <p>2. Команда <code>transform: translate(-50%, -50%)</code> заставляет блок отъехать назад ровно на <strong>половину своей собственной ширины и высоты</strong>. Теперь в центре оказывается не его угол, а его середина!</p>\n        </div>\n    </div>\n\n    \n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05); height: 150px; position: relative;">\n        <strong>Визуальный пример:</strong>\n        <div style="position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); padding: 10px 20px; background: var(--primary); color: white; border-radius: 8px; font-weight: bold;">\n            Я в идеальном центре\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай заголовок <code>h1</code> и отцентрируй его через <code>text-align</code>.</li>\n        <li>Создай <code>div</code> с ярким фоном, дай ему ширину <code>200px</code> и отцентрируй его через <code>margin: 0 auto</code>.</li>\n        <li>Сделай "мишень":\n            <ul>\n                <li>Создай большой темный квадрат (<code>relative</code>).</li>\n                <li>Внутри него создай маленький белый круг (<code>absolute</code>).</li>\n                <li>Используй <code>top</code>, <code>left</code> и <code>translate</code>, чтобы поместить круг идеально в центр квадрата.</li>\n            </ul>\n        </li>\n    </ol>\n</div>', 24, 1, '2026-04-24 01:50:55', '2026-04-24 07:06:44'),
	(25, 1, 9, 'Урок 9.1: Flex Container', 'urok-91-flex-container', '<section id="lesson-9-1">\n    <h2>🧩 Урок 9.1: Flex Container (Основы Flexbox)</h2>\n    <p>Flexbox превращает обычный блок в «умный контейнер». Как только ты говоришь блоку <code>display: flex</code>, все элементы внутри него становятся послушными и начинают выстраиваться в ряд автоматически.</p>\n\n    <h3>1. Главное правило: Родитель и Дети</h3>\n    <p>Во Flexbox всё управление идет через <strong>Родителя</strong> (Flex Container). Мы даем команды родителю, а <strong>Дети</strong> (Flex Items) послушно их выполняют.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.container</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>; <span class="hl-comm">/* Магия включена! */</span>\n}</code></pre>\n\n    <h3>2. Оси: Главная и Поперечная</h3>\n    <p>Внутри флекс-контейнера всегда есть две невидимые линии — оси. По умолчанию <strong>Главная ось</strong> идет слева направо, а <strong>Поперечная</strong> — сверху вниз.</p>\n    \n    \n\n    <h3>3. Выравнивание по главной оси (justify-content)</h3>\n    <p>Это свойство управляет тем, как элементы распределяются <strong>по горизонтали</strong> (если ось стандартная). Основные значения:</p>\n    <ul>\n        <li><code>flex-start</code> — все в начале (по умолчанию).</li>\n        <li><code>flex-end</code> — все в конце.</li>\n        <li><code>center</code> — все ровно в центре.</li>\n        <li><code>space-between</code> — первый в начале, последний в конце, остальные равномерно между ними.</li>\n        <li><code>space-around</code> — пустое место распределяется вокруг каждого элемента.</li>\n    </ul>\n\n    \n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.container</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>;\n    <span class="hl-attr">justify-content</span>: <span class="hl-str">space-between</span>;\n}</code></pre>\n\n    <h3>4. Выравнивание по поперечной оси (align-items)</h3>\n    <p>Это свойство управляет тем, как элементы стоят <strong>по вертикали</strong>. Самое полезное значение здесь — <code>center</code>. Оно наконец-то позволяет легко центрировать элементы по высоте!</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.container</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>;\n    <span class="hl-attr">align-items</span>: <span class="hl-str">center</span>; <span class="hl-comm">/* Все дети встанут ровно по середине высоты */</span>\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Супер-прием:</strong> Хочешь идеальный центр всего одной строчкой? \n            Задай родителю <code>display: flex; justify-content: center; align-items: center;</code>. Больше никаких <code>transform</code> и <code>translate</code> не нужно!\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальный пример (display: flex + space-around):</strong>\n        <div style="display: flex; justify-content: space-around; align-items: center; background: white; padding: 15px; border-radius: 8px; margin-top: 10px; height: 80px; border: 1px solid #ddd;">\n            <div style="width: 40px; height: 40px; background: #8b5cf6; border-radius: 4px;"></div>\n            <div style="width: 40px; height: 40px; background: #ec4899; border-radius: 4px;"></div>\n            <div style="width: 40px; height: 40px; background: #10b981; border-radius: 4px;"></div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>flex.html</code>.</li>\n        <li>Создай <code>&lt;nav class="menu"&gt;</code>, а внутри него 4 ссылки <code>&lt;a&gt;</code>.</li>\n        <li>Сделай меню флекс-контейнером (<code>display: flex</code>).</li>\n        <li>Используй <code>justify-content: center</code>, чтобы поставить все ссылки по центру страницы.</li>\n        <li>Добавь в CSS для меню <code>height: 100px</code> и любой фон.</li>\n        <li>Используй <code>align-items: center</code>, чтобы ссылки не "прилипали" к верху, а встали по центру высоты меню.</li>\n        <li>Поменяй <code>justify-content</code> на <code>space-between</code> и посмотри, как ссылки разлетятся по краям.</li>\n    </ol>\n</div>', 25, 1, '2026-04-24 01:50:55', '2026-04-24 07:08:02'),
	(26, 1, 9, 'Урок 9.2: Flex Items', 'urok-92-flex-items', '<section id="lesson-9-2">\n    <h2>👶 Урок 9.2: Flex Items (Свойства "детей")</h2>\n    <p>Если <code>display: flex</code> дает команды всем сразу, то свойства из этого урока позволяют настроить каждый элемент по отдельности. Это дает полный контроль над тем, как блоки делят между собой пространство.</p>\n\n    <h3>1. Гибкость (flex-grow)</h3>\n    <p>Это свойство определяет, какую часть свободного места заберет себе элемент. По умолчанию оно равно <code>0</code> (элемент не растет). Если задать <code>flex-grow: 1</code>, элемент растянется и займет всё доступное пустое место.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.item-main</span> {\n    <span class="hl-attr">flex-grow</span>: <span class="hl-str">1</span>; <span class="hl-comm">/* Заберет всё свободное пространство */</span>\n}</code></pre>\n\n    \n\n    <h3>2. Базовый размер (flex-basis)</h3>\n    <p>Это начальный размер элемента до того, как он начнет расти или сжиматься. Это почти то же самое, что <code>width</code>, но специально для Flexbox.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.item-sidebar</span> {\n    <span class="hl-attr">flex-basis</span>: <span class="hl-str">200px</span>;\n}</code></pre>\n\n    <h3>3. Личный порядок (order)</h3>\n    <p>Это настоящая магия. Ты можешь изменить порядок элементов на экране, не меняя их местами в HTML-коде. По умолчанию у всех <code>order: 0</code>. Чем больше число, тем дальше элемент в очереди.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.item-first</span> {\n    <span class="hl-attr">order</span>: <span class="hl-str">-1</span>; <span class="hl-comm">/* Прыгнет в самое начало */</span>\n}</code></pre>\n\n    \n\n    <h3>4. Личное выравнивание (align-self)</h3>\n    <p>Если родитель сказал всем стоять по центру (<code>align-items: center</code>), но один элемент хочет «прижаться» к низу, он может использовать <code>align-self</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.rebel-item</span> {\n    <span class="hl-attr">align-self</span>: <span class="hl-str">flex-end</span>; <span class="hl-comm">/* Уйдет вниз вопреки приказу родителя */</span>\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Шпаргалка "flex":</strong> Разработчики часто используют сокращение <code>flex: 1 0 auto;</code>. \n            Первая цифра — это <b>grow</b> (расти), вторая — <b>shrink</b> (сжиматься), третье — <b>basis</b> (размер).\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Визуальный пример (flex-grow):</strong>\n        <div style="display: flex; gap: 10px; background: white; padding: 10px; border-radius: 8px; border: 1px solid #ddd;">\n            <div style="padding: 10px; background: #8b5cf6; color: white; border-radius: 4px;">Обычный</div>\n            <div style="padding: 10px; background: #ec4899; color: white; border-radius: 4px; flex-grow: 1; text-align: center;">Я забираю всё место (flex-grow: 1)</div>\n            <div style="padding: 10px; background: #10b981; color: white; border-radius: 4px;">Обычный</div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>items.html</code> с контейнером и тремя блоками внутри.</li>\n        <li>Сделай контейнер флексовым (<code>display: flex</code>) и задай ему высоту <code>200px</code>.</li>\n        <li>Второму блоку задай <code>flex-grow: 1</code>. Посмотри, как он "съел" всё свободное пространство.</li>\n        <li>Третьему блоку задай <code>order: -1</code>. Теперь он стал первым?</li>\n        <li>Первому блоку задай <code>align-self: flex-end</code>. Он должен "упасть" на дно контейнера, пока остальные стоят сверху.</li>\n        <li><strong>Супер-задача:</strong> Попробуй сделать так, чтобы средний блок занимал в 2 раза больше места, чем остальные (используй <code>flex-grow: 2</code> для него и <code>flex-grow: 1</code> для других).</li>\n    </ol>\n</div>', 26, 1, '2026-04-24 01:50:55', '2026-04-24 07:10:46'),
	(27, 1, 9, 'Урок 9.3: Практика Flexbox', 'urok-93-praktika-flexbox', '<section id="lesson-9-3">\n    <h2>🏗️ Урок 9.3: Направление и Сетки (Практика)</h2>\n    <p>До этого момента наши элементы всегда выстраивались в ряд. Но Flexbox умеет гораздо больше. Мы научимся превращать строки в колонки, разрешать элементам перепрыгивать на новую строку и делать ровные промежутки между ними.</p>\n\n    <h3>1. Направление (flex-direction)</h3>\n    <p>По умолчанию это свойство равно <code>row</code> (строка). Но если ты изменишь его на <code>column</code>, дети встанут друг под другом. Это супер-полезно для мобильных версий сайтов!</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.container</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>;\n    <span class="hl-attr">flex-direction</span>: <span class="hl-str">column</span>; <span class="hl-comm">/* Теперь это колонка */</span>\n}</code></pre>\n\n    \n\n    <h3>2. Перенос (flex-wrap)</h3>\n    <p>По умолчанию Flexbox пытается втиснуть все элементы в одну линию, даже если они там не помещаются. Чтобы элементы вели себя как текст и переносились на новую строку, используй <code>flex-wrap: wrap</code>.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.grid</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>;\n    <span class="hl-attr">flex-wrap</span>: <span class="hl-str">wrap</span>; <span class="hl-comm">/* Элементы будут перепрыгивать вниз */</span>\n}</code></pre>\n\n    \n\n    <h3>3. Умные отступы (gap)</h3>\n    <p>Раньше нам приходилось мучаться с <code>margin</code>, чтобы блоки не слипались. Теперь есть свойство <code>gap</code>. Оно создает ровные пустые промежутки <strong>только между</strong> элементами, не добавляя лишнего места по краям контейнера.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.container</span> {\n    <span class="hl-attr">display</span>: <span class="hl-str">flex</span>;\n    <span class="hl-attr">gap</span>: <span class="hl-str">20px</span>; <span class="hl-comm">/* Промежуток между всеми детьми */</span>\n}</code></pre>\n\n    \n\n    <div class="alert alert-important">\n        <span>🎨</span>\n        <div>\n            <strong>Практический совет:</strong> Используй <code>gap</code> всегда, когда тебе нужно сделать сетку из карточек. Это в 10 раз проще, чем высчитывать отступы через <code>margin</code>.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Пример реальной сетки карточек:</strong>\n        <div style="display: flex; flex-wrap: wrap; gap: 10px; margin-top: 10px;">\n            <div style="flex: 1 1 100px; height: 60px; background: #8b5cf6; border-radius: 6px; display: flex; align-items: center; justify-content: center; color: white;">Карта 1</div>\n            <div style="flex: 1 1 100px; height: 60px; background: #ec4899; border-radius: 6px; display: flex; align-items: center; justify-content: center; color: white;">Карта 2</div>\n            <div style="flex: 1 1 100px; height: 60px; background: #10b981; border-radius: 6px; display: flex; align-items: center; justify-content: center; color: white;">Карта 3</div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>shop.html</code>.</li>\n        <li>Сделай контейнер <code>&lt;div class="products"&gt;</code> и положи в него 6 карточек товара (<code>&lt;div class="card"&gt;</code>).</li>\n        <li>В CSS для <code>.products</code>:\n            <ul>\n                <li>Включи флекс (<code>display: flex</code>).</li>\n                <li>Разреши перенос (<code>wrap</code>).</li>\n                <li>Задай промежуток <code>gap: 20px</code>.</li>\n            </ul>\n        </li>\n        <li>Для <code>.card</code> задай ширину <code>30%</code> (чтобы в ряд помещалось 3 штуки).</li>\n        <li><strong>Бонус:</strong> С помощью медиа-запроса (или просто вручную попробуй) измени <code>flex-direction</code> на <code>column</code>. Заметил, как сайт превратился в мобильную версию?</li>\n    </ol>\n</div>', 27, 1, '2026-04-24 01:50:55', '2026-04-24 07:14:15'),
	(28, 1, 10, 'Урок 10.1: Анимации и Трансформации', 'urok-101-animacii-i-transformacii', '<section id="lesson-10-1">\n    <h2>✨ Урок 10.1: Плавные переходы (Transitions)</h2>\n    <p>До этого момента все изменения на наших сайтах происходили мгновенно: навел курсор — и цвет кнопки тут же переключился. Свойство <code>transition</code> позволяет растянуть это изменение во времени, делая его приятным для глаз.</p>\n\n    <h3>1. Как работает Transition</h3>\n    <p>Чтобы магия сработала, нам нужны две вещи: состояние «ДО» (обычный вид) и состояние «ПОСЛЕ» (например, при наведении курсора — <code>:hover</code>).</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.button</span> {\n    <span class="hl-attr">background</span>: <span class="hl-str">#4f46e5</span>;\n    <span class="hl-comm">/* Что анимируем | Время | Тип анимации */</span>\n    <span class="hl-attr">transition</span>: <span class="hl-str">background 0.3s ease</span>;\n}\n\n<span class="hl-tag">.button:hover</span> {\n    <span class="hl-attr">background</span>: <span class="hl-str">#ec4899</span>;\n}</code></pre>\n\n    \n\n    <h3>2. Основные параметры</h3>\n    <ul>\n        <li><strong>Property:</strong> Что именно анимируем (<code>color</code>, <code>width</code>, <code>opacity</code>). Если хочешь всё сразу — пиши <code>all</code>.</li>\n        <li><strong>Duration:</strong> Время анимации. Обычно это доли секунды (<code>0.3s</code>) или целые секунды (<code>1s</code>).</li>\n        <li><strong>Timing Function:</strong> Характер движения. <code>ease</code> (плавный старт и конец), <code>linear</code> (равномерно), <code>ease-in</code> (ускорение).</li>\n    </ul>\n\n    <h3>3. Что можно анимировать?</h3>\n    <p>Почти всё, что имеет числовые значения или цвета:</p>\n    <ul>\n        <li>Размеры: <code>width</code>, <code>height</code>, <code>font-size</code>.</li>\n        <li>Отступы: <code>padding</code>, <code>margin</code>.</li>\n        <li>Цвета: <code>color</code>, <code>background-color</code>, <code>border-color</code>.</li>\n        <li>Прозрачность: <code>opacity</code>.</li>\n    </ul>\n\n    <div class="alert alert-important">\n        <span>⚠️</span>\n        <div>\n            <strong>Важно:</strong> Свойство <code>transition</code> нужно писать в основном состоянии элемента (не в <code>:hover</code>). Тогда анимация будет работать в обе стороны: и когда ты наводишь курсор, и когда убираешь его.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Интерактивный пример:</strong>\n        <p style="font-size: 0.9em; color: var(--text-muted);">Наведи на карточку ниже:</p>\n        <div style="width: 200px; padding: 20px; background: white; border: 2px solid #ddd; border-radius: 10px; cursor: pointer; transition: all 0.4s ease-out; margin: 10px auto; text-align: center;" \n             onmouseover="this.style.borderColor=\'#4f46e5\'; this.style.transform=\'translateY(-10px)\'; this.style.boxShadow=\'0 10px 20px rgba(0,0,0,0.1)\';" \n             onmouseout="this.style.borderColor=\'#ddd\'; this.style.transform=\'translateY(0)\'; this.style.boxShadow=\'none\';">\n            <h4 style="margin: 0; transition: color 0.4s;">Карточка</h4>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Открой свой файл <code>shop.html</code> с карточками товаров.</li>\n        <li>Для класса <code>.card</code> добавь свойство <code>transition: all 0.3s ease;</code>.</li>\n        <li>Создай правило <code>.card:hover</code>, в котором измени:\n            <ul>\n                <li>Цвет фона.</li>\n                <li>Цвет текста заголовка.</li>\n                <li>Добавь или измени тень (<code>box-shadow</code>).</li>\n            </ul>\n        </li>\n        <li>Сделай кнопку «Купить» плавно увеличивающейся при наведении (подсказка: измени <code>padding</code> или <code>font-size</code>).</li>\n        <li><strong>Эксперимент:</strong> Попробуй поставить время <code>3s</code> (3 секунды) и посмотри, как медленно будет меняться цвет.</li>\n    </ol>\n</div>', 28, 1, '2026-04-24 01:50:55', '2026-04-24 07:17:17'),
	(29, 1, 10, 'Урок 10.2: Трансформации (Transform)', 'urok-102-transformacii-transform', '<section id="lesson-10-2">\n    <h2>🔄 Урок 10.2: Трансформации (Transform)</h2>\n    <p>Свойство <code>transform</code> позволяет видоизменять элементы: крутить их, растягивать, сжимать и перемещать в 2D и 3D пространстве. Главный плюс — это не влияет на соседние блоки, они остаются на своих местах.</p>\n\n    <h3>1. Масштабирование (scale)</h3>\n    <p>Позволяет увеличить или уменьшить элемент. <code>scale(1.2)</code> — увеличит на 20%, а <code>scale(0.5)</code> — уменьшит в два раза.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.card:hover</span> {\n    <span class="hl-attr">transform</span>: <span class="hl-str">scale(1.1)</span>; <span class="hl-comm">/* Карточка слегка увеличится при наведении */</span>\n}</code></pre>\n\n    <h3>2. Поворот (rotate)</h3>\n    <p>Поворачивает элемент на заданный угол. Значение указывается в градусах (<code>deg</code>).</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.icon:hover</span> {\n    <span class="hl-attr">transform</span>: <span class="hl-str">rotate(15deg)</span>; <span class="hl-comm">/* Наклон вправо */</span>\n}</code></pre>\n\n    \n\n    <h3>3. Перемещение (translate)</h3>\n    <p>Мы уже встречали его в уроке про центрирование. Оно двигает элемент по осям X (влево-вправо) и Y (вверх-вниз).</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.link:hover</span> {\n    <span class="hl-attr">transform</span>: <span class="hl-str">translateX(10px)</span>; <span class="hl-comm">/* Сдвиг вправо на 10 пикселей */</span>\n}</code></pre>\n\n    <h3>4. Комбинирование свойств</h3>\n    <p>Ты можешь использовать несколько трансформаций одновременно. Просто перечисли их через пробел в одном свойстве.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.box:hover</span> {\n    <span class="hl-attr">transform</span>: <span class="hl-str">rotate(45deg) scale(1.5) translateX(20px)</span>;\n}</code></pre>\n\n    <div class="alert alert-important">\n        <span>💡</span>\n        <div>\n            <strong>Секрет успеха:</strong> Всегда сочетай <code>transform</code> со свойством <code>transition</code> из прошлого урока. Тогда изменения будут не резкими, а плавными и красивыми.\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05);">\n        <strong>Демонстрация (Наведи на элементы):</strong>\n        <div style="display: flex; gap: 20px; justify-content: center; padding: 20px;">\n            <div style="width: 60px; height: 60px; background: #8b5cf6; border-radius: 8px; transition: 0.3s; display: flex; align-items: center; justify-content: center; color: white; cursor: pointer;" onmouseover="this.style.transform=\'rotate(45deg)\'" onmouseout="this.style.transform=\'rotate(0)\'">Rotate</div>\n            <div style="width: 60px; height: 60px; background: #ec4899; border-radius: 8px; transition: 0.3s; display: flex; align-items: center; justify-content: center; color: white; cursor: pointer;" onmouseover="this.style.transform=\'scale(1.3)\'" onmouseout="this.style.transform=\'scale(1)\'">Scale</div>\n            <div style="width: 60px; height: 60px; background: #10b981; border-radius: 8px; transition: 0.3s; display: flex; align-items: center; justify-content: center; color: white; cursor: pointer;" onmouseover="this.style.transform=\'translateY(-10px)\'" onmouseout="this.style.transform=\'translateY(0)\'">Move</div>\n        </div>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>transform.html</code>.</li>\n        <li>Создай 3 квадрата разных цветов.</li>\n        <li>Для первого квадрата настрой плавный поворот на 360 градусов при наведении (<code>rotate(360deg)</code>).</li>\n        <li>Для второго квадрата сделай эффект «увеличения кнопки» при наведении (<code>scale(1.2)</code>).</li>\n        <li>Третий квадрат должен плавно «отпрыгивать» в сторону при наведении (<code>translateX</code>).</li>\n        <li><strong>Бонусное задание:</strong> Попробуй сделать так, чтобы при наведении на картинку она одновременно увеличивалась и немного поворачивалась.</li>\n    </ol>\n</div>', 29, 1, '2026-04-24 01:50:55', '2026-04-24 07:29:34'),
	(30, 1, 10, 'Урок 10.3: Сложные анимации (@keyframes)', 'urok-103-sloznye-animacii-at-keyframes', '<section id="lesson-10-3">\n    <h2>🎬 Урок 10.3: Сложные анимации (@keyframes)</h2>\n    <p>Иногда нужно, чтобы элемент двигался сам по себе, без участия пользователя. Например, пульсирующая кнопка "Купить" или крутящийся значок загрузки. Для этого в CSS используются <strong>Ключевые кадры</strong>.</p>\n\n    <h3>1. Создание сценария (@keyframes)</h3>\n    <p>Сначала мы описываем сценарий: как должен выглядеть элемент в начале, в середине и в конце пути. Мы даем этой анимации имя.</p>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">@keyframes</span> <span class="hl-str">pulse</span> {\n    <span class="hl-attr">0%</span> { <span class="hl-attr">transform</span>: <span class="hl-str">scale(1)</span>; }\n    <span class="hl-attr">50%</span> { <span class="hl-attr">transform</span>: <span class="hl-str">scale(1.1)</span>; }\n    <span class="hl-attr">100%</span> { <span class="hl-attr">transform</span>: <span class="hl-str">scale(1)</span>; }\n}</code></pre>\n\n    \n\n    <h3>2. Запуск анимации (animation)</h3>\n    <p>Чтобы сценарий ожил, его нужно прикрепить к элементу с помощью свойства <code>animation</code>.</p>\n    <ul>\n        <li><code>animation-name</code> — имя сценария (у нас это <em>pulse</em>).</li>\n        <li><code>animation-duration</code> — сколько длится один цикл (например, <em>2s</em>).</li>\n        <li><code>animation-iteration-count</code> — сколько раз повторить. Пиши <code>infinite</code>, если хочешь вечную анимацию.</li>\n    </ul>\n\n    <pre><button class="try-it-btn" onclick="openPlayground(this)"><span>🚀</span> Попробовать</button><code><span class="hl-tag">.sale-badge</span> {\n    <span class="hl-attr">animation</span>: <span class="hl-str">pulse 2s infinite ease-in-out</span>;\n}</code></pre>\n\n    <h3>3. Краткая запись</h3>\n    <p>Как и в случае с отступами, все параметры можно записать в одну строку: <br>\n    <code>animation: [имя] [время] [тип сглаживания] [повторы];</code></p>\n\n    \n\n    <div class="alert alert-important">\n        <span>🤖</span>\n        <div>\n            <strong>В чем разница?</strong> \n            <code>transition</code> запускается только при смене состояния (например, <code>:hover</code>). \n            <code>animation</code> запускается сама и может иметь сколько угодно промежуточных этапов (0%, 25%, 50%, 75%, 100%).\n        </div>\n    </div>\n\n    <div style="padding: 16px; border: 1px dashed var(--primary); border-radius: 12px; margin: 16px 0; background: rgba(79, 70, 229, 0.05); text-align: center;">\n        <strong>Пример "Живой" кнопки:</strong>\n        <style>\n            @keyframes heartbeat {\n                0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(79, 70, 229, 0.4); }\n                70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(79, 70, 229, 0); }\n                100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(79, 70, 229, 0); }\n            }\n        </style>\n        <button style="margin-top: 10px; padding: 12px 24px; background: var(--primary); color: white; border: none; border-radius: 8px; font-weight: bold; cursor: pointer; animation: heartbeat 1.5s infinite;">ВНИМАНИЕ!</button>\n    </div>\n</section>\n\n<div class="task-box">\n    <h2>🚀 Практическое задание</h2>\n    <ol>\n        <li>Создай файл <code>animation.html</code>.</li>\n        <li>Создай <code>@keyframes</code> с именем <code>bounce</code> (прыжок). Пусть на 0% и 100% элемент стоит на месте, а на 50% — поднимается вверх на <code>-30px</code> (используй <code>translateY</code>).</li>\n        <li>Примени эту анимацию к картинке или блоку, сделай её бесконечной (<code>infinite</code>).</li>\n        <li>Создай <code>@keyframes</code> для вращения (<code>rotate(360deg)</code>) и примени его к какому-нибудь круглому элементу.</li>\n        <li><strong>Творческое задание:</strong> Сделай «светофор» — один блок, который плавно меняет цвет фона: Красный -> Желтый -> Зеленый и обратно.</li>\n    </ol>\n</div>', 30, 1, '2026-04-24 01:50:55', '2026-04-24 07:49:16'),
	(31, 1, 11, 'Финальный проект — Твой личный сайт', 'finalnyi-proekt-tvoi-lichnyi-sait', '<section id="final-project">\n    <div style="text-align: center; padding: 40px 20px; background: linear-gradient(135deg, rgba(79, 70, 229, 0.1), rgba(236, 72, 153, 0.1)); border-radius: 24px; border: 2px solid var(--primary); margin-bottom: 30px;">\n        <h1 style="font-size: 2.5rem; margin-bottom: 10px;">🏆 Модуль 11: Финальный проект</h1>\n        <p style="font-size: 1.2rem; color: var(--text-main);">Поздравляю! Ты прошел путь от первой строчки <code>&lt;html&gt;</code> до живых анимаций. Пришло время создать твой первый настоящий сайт.</p>\n    </div>\n\n    <h2>📌 Твое задание</h2>\n    <p>Тебе нужно разработать многостраничный сайт (минимум 3 страницы) на любую интересную тебе тему. Это может быть портфолио, фан-сайт игры, сайт о твоем питомце или проект для школьного кружка.</p>\n\n    <h3>🛠 Технические требования к проекту:</h3>\n    \n    <div class="task-box" style="background: #f9fafb; color: #1f2937; border-left: 5px solid #10b981; padding: 20px; border-radius: 8px; margin: 20px 0; box-shadow: 0 2px 5px rgba(0,0,0,0.05);">\n    <ul style="margin: 0; padding-left: 20px; line-height: 1.6;">\n        <li style="margin-bottom: 10px;"><strong>Многостраничность:</strong> Минимум 3 файла (<code>index.html</code>, <code>about.html</code>, <code>contacts.html</code>), связанных общим меню.</li>\n        <li style="margin-bottom: 10px;"><strong>Семантика HTML5:</strong> Использование тегов <code>&lt;header&gt;</code>, <code>&lt;nav&gt;</code>, <code>&lt;main&gt;</code>, <code>&lt;section&gt;</code> и <code>&lt;footer&gt;</code>.</li>\n        <li style="margin-bottom: 10px;"><strong>Оформление CSS:</strong> Все стили должны быть в отдельном файле <code>style.css</code>.</li>\n        <li style="margin-bottom: 10px;"><strong>Верстка на Flexbox:</strong> Хотя бы один блок должен быть сделан на флексах (например, карточки или меню).</li>\n        <li style="margin-bottom: 10px;"><strong>Анимации:</strong> Минимум 2 элемента с плавными переходами <code>transition</code> или анимацией <code>@keyframes</code>.</li>\n        <li style="margin-bottom: 0;"><strong>Форма:</strong> На странице контактов должна быть рабочая HTML-форма с валидацией полей.</li>\n    </ul>\n</div>\n\n    \n\n    <h2>🗺 Дорожная карта разработки</h2>\n    <div style="display: flex; flex-direction: column; gap: 15px; margin: 20px 0;">\n        <div style="display: flex; align-items: flex-start; gap: 15px;">\n            <div style="background: var(--primary); color: white; width: 30px; height: 30px; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; font-weight: bold;">1</div>\n            <div><strong>Проектирование:</strong> Выбери тему и набросай на бумаге, где будут кнопки, а где текст.</div>\n        </div>\n        <div style="display: flex; align-items: flex-start; gap: 15px;">\n            <div style="background: var(--primary); color: white; width: 30px; height: 30px; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; font-weight: bold;">2</div>\n            <div><strong>HTML-каркас:</strong> Создай файлы и наполни их контентом. Проверь, чтобы ссылки работали.</div>\n        </div>\n        <div style="display: flex; align-items: flex-start; gap: 15px;">\n            <div style="background: var(--primary); color: white; width: 30px; height: 30px; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; font-weight: bold;">3</div>\n            <div><strong>CSS-магия:</strong> Добавь цвета, шрифты Google Fonts и выровняй блоки по сетке.</div>\n        </div>\n        <div style="display: flex; align-items: flex-start; gap: 15px;">\n            <div style="background: var(--primary); color: white; width: 30px; height: 30px; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; font-weight: bold;">4</div>\n            <div><strong>Полировка:</strong> Добавь тени, скругления и плавные ховер-эффекты.</div>\n        </div>\n    </div>\n\n    \n\n    <div class="alert alert-important">\n        <span>✨</span>\n        <div>\n            <strong>Совет:</strong> Не старайся сделать всё идеально сразу. Сначала сделай работающую структуру, а потом добавляй красоту. Твой код — это твое творчество!\n        </div>\n    </div>\n\n<div style="text-align: center; margin-top: 40px;">\n        <p>Готов начать? Создавай новую папку и поехали!</p>\n        <button id="finalBtn" style="padding: 15px 30px; font-size: 1.2rem; background: #10b981; color: white; border: none; border-radius: 50px; cursor: pointer; font-weight: bold; box-shadow: 0 4px 15px rgba(16, 185, 129, 0.3);">🚀 ПРИСТУПИТЬ К ПРОЕКТУ</button>\n    </div>\n\n</section>\n\n<div class="fp-modal-overlay" id="fpModalOverlay" style="z-index: 99999;">\n    <div class="fp-modal-box">\n        <div class="fp-modal-header">\n            <div class="fp-modal-icon">🚀</div>\n            <h3 class="fp-modal-title">Финальный проект!</h3>\n        </div>\n        <div class="fp-modal-content">\n            <p>Ты на финишной прямой. Помни: код — это поэзия, а ты — автор. Удачи!</p>\n        </div>\n        <div class="fp-modal-actions">\n            <button class="fp-modal-btn" id="closeFpModal">Погнали!</button>\n        </div>\n    </div>\n</div>\n\n<style>\n/* Custom Modal Styles */\n.fp-modal-overlay {\n    position: fixed;\n    top: 0;\n    left: 0;\n    width: 100vw;\n    height: 100vh;\n    background: rgba(0, 0, 0, 0.8); /* Затемнение фона */\n    display: none; /* Скрыто по умолчанию */\n    align-items: center;\n    justify-content: center;\n    z-index: 2000; /* Чтобы быть выше всего */\n    backdrop-filter: blur(5px); /* Легкое размытие */\n}\n\n.fp-modal-box {\n    background: #1a202c; /* Темный фон, как на сайте */\n    border-radius: 12px;\n    padding: 30px;\n    max-width: 400px;\n    width: 90%;\n    color: white;\n    text-align: center;\n    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.4);\n    border: 1px solid #2d3748;\n}\n\n.fp-modal-header {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 10px;\n    margin-bottom: 20px;\n}\n\n.fp-modal-icon {\n    font-size: 3rem;\n}\n\n.fp-modal-title {\n    font-size: 1.5rem;\n    margin: 0;\n}\n\n.fp-modal-content {\n    font-size: 1.1rem;\n    line-height: 1.6;\n    margin-bottom: 25px;\n}\n\n.fp-modal-btn {\n    padding: 12px 24px;\n    font-size: 1.1rem;\n    background: #8b5cf6; /* Фиолетовая, как кнопка "Завершить урок" */\n    color: white;\n    border: none;\n    border-radius: 50px;\n    cursor: pointer;\n    font-weight: bold;\n    box-shadow: 0 4px 10px rgba(139, 92, 246, 0.3);\n}\n</style>\n<script>\n// Get elements\nconst finalBtn = document.getElementById(\'finalBtn\'); // Замените на ID вашей зеленой кнопки\nconst fpModalOverlay = document.getElementById(\'fpModalOverlay\');\nconst closeFpModal = document.getElementById(\'closeFpModal\');\n\nif (finalBtn && fpModalOverlay && closeFpModal) {\n    // Show modal on button click\n    finalBtn.addEventListener(\'click\', (e) => {\n        // e.preventDefault(); // Разкомментируйте, если это ссылка\n        showFpModal();\n    });\n\n    // Hide modal on close button click\n    closeFpModal.addEventListener(\'click\', hideFpModal);\n\n    // Hide modal on overlay click (optional)\n    fpModalOverlay.addEventListener(\'click\', (e) => {\n        if (e.target === fpModalOverlay) {\n            hideFpModal();\n        }\n    });\n}\n\nfunction showFpModal() {\n    fpModalOverlay.style.display = \'flex\';\n}\n\nfunction hideFpModal() {\n    fpModalOverlay.style.display = \'none\';\n}\n</script>\n\n<script>\n// Ждем полной загрузки страницы\ndocument.addEventListener(\'DOMContentLoaded\', () => {\n    const finalBtn = document.getElementById(\'finalBtn\');\n    const modal = document.getElementById(\'fpModalOverlay\');\n    const closeBtn = document.getElementById(\'closeFpModal\');\n\n    console.log(\'Кнопка найдена:\', finalBtn);\n    console.log(\'Модалка найдена:\', modal);\n\n    if (finalBtn && modal) {\n        finalBtn.onclick = (e) => {\n            console.log(\'Клик по кнопке зафиксирован!\');\n            modal.style.display = \'flex\';\n        };\n\n        closeBtn.onclick = () => {\n            modal.style.display = \'none\';\n        };\n    } else {\n        console.error(\'Ошибка: Не удалось найти кнопку или модальное окно по ID!\');\n    }\n});\n</script>\n\n', 31, 1, '2026-04-24 09:17:36', '2026-04-25 00:25:38');
